    clinic.test <- Clinic.224.df[idx.test,]
    clinic.valid <- Clinic.88.df
    
    # Load Cox P-value-based feature ranking for the current training set
    EBS.i <- colnames(Rad.train)[sample(ncol(Rad.train))]
    
    # Select the number of features
    
    # Randomly select the number of features from the candidate set with the maximum C-index
    numOfFeats[i] <- sample(numOfFeatsSet,1)
    Feats <- EBS.i[1:numOfFeats[i]]
    
    # Build the model and make predictions using the selected features
    RadC.train <- data.frame(Rad.train[,Feats],
                             time = clinic.train$surv.clinical.Time.Months,
                             status = clinic.train$surv.clinical.Event)
    RadC.test <- data.frame(Rad.test[,Feats],
                            time = clinic.test$surv.clinical.Time.Months,
