        # HR.valid
        lp.RS.valid.sd <- (lp.RS.valid - min(lp.RS.valid))/(max(lp.RS.valid) - min(lp.RS.valid))
        df.valid <- data.frame(df.valid, score.sd = lp.RS.valid.sd)
        res.mat[i,"HR.valid"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                               data = df.valid))$coefficients[2]
    }else{
        print(paste0("NumOfFeats: ", numOfFeats[i], 
                     ", No solution!"))
        numOfFailed <- numOfFailed + 1
    }
}

# Summarize average performance
meanRes <- rep(0, length = 24)
medianRes <- rep(0, length = 24)
sdRes <- rep(0, length = 24)
RSDRes <- rep(0, length = 24)
for(i in seq_len(ncol(res.mat))){
    meanRes[i] <- mean(res.mat[,i], na.rm = TRUE)
    medianRes[i] <- median(res.mat[,i], na.rm = TRUE)
    sdRes[i] <- sd(res.mat[,i], na.rm = TRUE)
    RSDRes[i] <- 100*sdRes[i]/meanRes[i]
}
res.mean <- data.frame(mean = meanRes,
                       median = medianRes,
                       sd = sdRes,
                       RSD = RSDRes)
rownames(res.mean) <- colnames(res.mat)

res.Rand.RSF <- list(res = res.mat,
                     res.mean = res.mean,
                     numOfFailed = numOfFailed,
                     numOfFeats = numOfFeats)


# 1.12 DeepSurv ---------------
# 1.12.1 Hyperparameter tuning for DeepSurv---------------
# load data 

# IBM.224.mat, Clinic.224.df, IBM.88.mat, Clinic.88.df
load(file = "./RData/NSCLC.IBM.224.88.clinic.224.88.RData")


# normalization
IBM.224.mat.sd <- scale(IBM.224.mat, center = TRUE, scale = TRUE)
IBM.88.mat.sd <- scale(IBM.88.mat, center = TRUE, scale = TRUE)


library(reticulate)
library(survivalmodels)
library(mlr3)
library(mlr3proba)
library(paradox) # Define and Work with Parameter Spaces for Complex Algorithms
library(mlr3tuning)
library(mlr3extralearners)## learners are stored in mlr3extralearners

# dataset
RadC.224 <- data.frame(IBM.224.mat.sd,
                       time = Clinic.224.df$surv.clinical.Time.Months,
                       status = Clinic.224.df$surv.clinical.Event)

## create our own task
task.NSCLC <- TaskSurv$new(id = "NSCLC", # task id
                           backend = RadC.224,  # data, data.table or data.frame
                           time = "time",  # Name of the column for event time
                           event = "status") # Name of the column giving the event indicator
# "0"/FALSE means alive (no event), "1"/TRUE means dead (event)

# Hyperparameter tuning
lrn.deepsurv <- lrn("surv.deepsurv", 
                    frac = 0.3,  # Fraction of data to use for validation dataset
                    early_stopping = TRUE, 
                    epochs = 500, 
                    batch_norm = TRUE # batch normalisation
                    # optimizer = "adam",
)

# lrn.deepsurv$param_set

search_space <- ps(
    ## p_dbl for numeric valued parameters
    activation = p_fct(levels = c("relu", "selu")),  
    dropout = p_dbl(lower = 0, upper = 0.8),  # 
    weight_decay = p_dbl(lower = 0, upper = 0.5), # Passed to all methods except rprop and sparse_adam
    # learning_rate = p_dbl(lower = 1e-4, upper = 1),
    learning_rate = p_dbl(lower = 1, upper = 9, trafo = function(x) exp(x)/exp(10)),
    optimizer = p_fct(levels = c("adam", "sgd")),
    # momentum = p_dbl(lower = 0, upper = 1), 
    
    ## p_int for integer valued parameters
    nodes = p_int(lower = 2, upper = 7), # the number of nodes in a layer
    k = p_int(lower = 1, upper = 4),  # the number of layers
    .extra_trafo = function(x, param_set) {
        # x$num_nodes = c()
        # n_layers = x$k
        # for(n_l in seq_len(n_layers)){
        #     x$num_nodes = c(x$num_nodes, sample(c(4,8,16,24,32,64),1))
        # }
        x$num_nodes = rep(2^(x$nodes), x$k)
        x$nodes = x$k = NULL
        # x$k = NULL
        if(x$optimizer == "sgd"){
            x$momentum = 0.8 #runif(1, 0.8,0.95)
        }
        return(x)
    }
)

## select holdout as the resampling strategy
resampling <- rsmp("cv", folds = 3)
resampling <- rsmp("repeated_cv", repeats = 5, folds = 3)

# hout = rsmp("holdout")
measure = msr("surv.cindex")

library("mlr3tuning")
# Terminate after a given time (TerminatorClockTime).
# Terminate after a given number of iterations (TerminatorEvals).
# Terminate after a specific performance has been reached (TerminatorPerfReached).
# Terminate when tuning does find a better configuration for a given number of iterations (TerminatorStagnation).
# A combination of the above in an ALL or ANY fashion (TerminatorCombo).
evals20 = trm("evals", n_evals = 2)
trm10 = trm("stagnation", iters = 3000, threshold = 1e-5)
trm.comb = trm("combo",
               list(
                   trm("clock_time", stop_time = Sys.time() + 72000),
                   trm("stagnation", iters = 6000, threshold = 1e-5)
               ), any = TRUE)

instance = TuningInstanceSingleCrit$new(
    task = task.NSCLC,
    learner = lrn.deepsurv,
    resampling = resampling,
    measure = measure,
    search_space = search_space,
    terminator = trm.comb#evals20#
)
instance

tuner = tnr("random_search", batch_size = 5)  # Maximum number of points to try in a batch.
tuner = tnr("grid_search",
            param_resolutions = c("dropout" = 20,
                                  "learning_rate" = 20,
                                  "weight_decay" = 10),
            batch_size = 5)  # Maximum number of points to try in a batch.
tuner$optimize(instance)
instance$result_learner_param_vals   # Optimal parameters
instance$result_y   # Optimal results
# as.data.table(instance$archive)  # All results
# instance$archive$benchmark_result


lrn.deepsurv$param_set$values = instance$result_learner_param_vals  # select optimal parameters

save(lrn.deepsurv, file = "./RData/lrn.deepsurv.None.NSCLC.IBM.224.88.clinic.224.88.RData")


