                               event = "status") # Name of the column giving the event indicator
    # "0"/FALSE means alive (no event), "1"/TRUE means dead (event)
    
    load(file = "./RData/lrn.deephit.CoxP.NSCLC.IBM.224.88.clinic.224.88.RData")
    # lrn.deephit$param_set$values
    lrn.cur = lrn.deephit
    
