medianRes <- rep(0, length = 24)
sdRes <- rep(0, length = 24)
RSDRes <- rep(0, length = 24)
for(i in seq_len(ncol(res.mat))){
    meanRes[i] <- mean(res.mat[,i], na.rm = TRUE)
    medianRes[i] <- median(res.mat[,i], na.rm = TRUE)
    sdRes[i] <- sd(res.mat[,i], na.rm = TRUE)
    RSDRes[i] <- 100*sdRes[i]/meanRes[i]
}
res.mean <- data.frame(mean = meanRes,
                       median = medianRes,
                       sd = sdRes,
                       RSD = RSDRes)
