library("mlr3tuning")

# load data 
# IBM.224.mat, Clinic.224.df, IBM.88.mat, Clinic.88.df
load(file = "./RData/NSCLC.IBM.224.88.clinic.224.88.RData")


# normalization
IBM.224.mat.sd <- scale(IBM.224.mat, center = TRUE, scale = TRUE)
IBM.88.mat.sd <- scale(IBM.88.mat, center = TRUE, scale = TRUE)

# Load predefined random train-test splits 
load(file = "./RData/rslist.NSCLC.IBM.224.88.clinic.224.88.RData")

# Load precomputed feature ranking based on Spearman correlation-enhanced Borda score
load(file = "./RData/ls.Spearman.EBS.NSCLC.IBM.224.88.clinic.224.88.RData")
# ls.Spearman.EBS
topN <- 106

# load deepsurv model
load(file = "./RData/lrn.deepsurv.Spearman.NSCLC.IBM.224.88.clinic.224.88.RData")
lrn.deepsurv$param_set$values
