        lp.RS.valid.sd <- (lp.RS.valid - min(lp.RS.valid))/(max(lp.RS.valid) - min(lp.RS.valid))
        df.valid <- data.frame(df.valid, score.sd = lp.RS.valid.sd)
        res.mat[i,"HR.valid"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                               data = df.valid))$coefficients[2]
    }else{
        print(paste0("No solution!"))
        numOfFailed <- numOfFailed + 1
    }
}

# Summarize average performance
meanRes <- rep(0, length = 24)
medianRes <- rep(0, length = 24)
sdRes <- rep(0, length = 24)
RSDRes <- rep(0, length = 24)
for(i in seq_len(ncol(res.mat))){
    meanRes[i] <- mean(res.mat[,i], na.rm = TRUE)
    medianRes[i] <- median(res.mat[,i], na.rm = TRUE)
    sdRes[i] <- sd(res.mat[,i], na.rm = TRUE)
    RSDRes[i] <- 100*sdRes[i]/meanRes[i]
}
res.mean <- data.frame(mean = meanRes,
                       median = medianRes,
                       sd = sdRes,
                       RSD = RSDRes)
rownames(res.mean) <- colnames(res.mat)

res.mRMR.CoxPH <- list(res = res.mat,
                          res.mean = res.mean,
                          numOfFailed = numOfFailed,
                          numOfFeats = numOfFeats)



# 5.10 survival SVM -------------
# load data 

# IBM.224.mat, Clinic.224.df, IBM.88.mat, Clinic.88.df
load(file = "./RData/NSCLC.IBM.224.88.clinic.224.88.RData")


# normalization
IBM.224.mat.sd <- scale(IBM.224.mat, center = TRUE, scale = TRUE)
IBM.88.mat.sd <- scale(IBM.88.mat, center = TRUE, scale = TRUE)

# Load predefined random train-test splits 
load(file = "./RData/rslist.NSCLC.IBM.224.88.clinic.224.88.RData")

# Load precomputed feature ranking based on mRMR-enhanced Borda score
load(file = "./RData/ls.mRMR.EBS.NSCLC.IBM.224.88.clinic.224.88.RData")
# ls.mRMR.EBS
topN <- 20

# repeat 100 times
N <- 100

# mod.mboost <- vector(mode = "list", length = N)

# Number of features ranging from 5 up to 50, with an increment of 5 features (n= 5, 10, 15, 20, … , 50). 
numOfFeatsSet <- seq(from = 5, to = 50, by = 5)
numOfFeats <- rep(NA, length = N)  # Store the number of selected features

# Candidate Gamma values
GammaSet <- c(0.001, 0.01, 0.1, 1, 10, 100, 1000)  

res.mat <- matrix(NA, nrow = N, ncol = 24)
colnames(res.mat) <- c("cindex.train", "AUC.1y.train", "AUC.3y.train",
                       "AUC.5y.train", "IAUC.train", "bs.train", "logrank.train", "HR.train",
                       "cindex.test",  "AUC.1y.test", "AUC.3y.test",  
                       "AUC.5y.test",  "IAUC.test", "bs.test", "logrank.test", "HR.test",
                       "cindex.valid", "AUC.1y.valid", "AUC.3y.valid", 
                       "AUC.5y.valid", "IAUC.valid", "bs.valid", "logrank.valid", "HR.valid")
GammaSel <- rep(NA, length = N)  # Store the Gamma value selected in each repeat
numOfFailed <- 0

for(i in seq_len(N)){
    print(paste0("N: ",i, " ------------"))
    
    idx.train <- rslist[[i]]$idx.train
    idx.test <- rslist[[i]]$idx.test
    
    Rad.train <- IBM.224.mat.sd[idx.train, ]
    Rad.test <- IBM.224.mat.sd[idx.test, ]
    Rad.valid <- IBM.88.mat.sd
    
    clinic.train <- Clinic.224.df[idx.train,]
    clinic.test <- Clinic.224.df[idx.test,]
    clinic.valid <- Clinic.88.df
    
    # Load Cox P-values for the current training set
    EBS.i <- ls.mRMR.EBS[[i]]
    
    # Randomly split the training set into five subsets and use 5-fold CV to select the number of features (nFeats) that maximizes the C-index on the training-test sets
    splt5 <- mySplit(clinic.train)
    
    # Select the number of features and Gamma hyperparameter
    Cindex.nFeats <- rep(0, length = length(numOfFeatsSet)) 
    GammaSel.nFeats <- rep(0, length = length(numOfFeatsSet)) 
    for(j in seq_len(length(numOfFeatsSet))){
        print(paste0("NumOfFeats: ", numOfFeatsSet[j]))
        Feats <- names(EBS.i)[1:numOfFeatsSet[j]]
        
        RadC.train <- data.frame(Rad.train[,Feats],
                                 time = clinic.train$surv.clinical.Time.Months,
                                 status = clinic.train$surv.clinical.Event)
        
        # Select Gamma hyperparameter
        Cindex.gamma <- rep(0, length = length(GammaSet))
        for(k in seq_len(length(GammaSet))){
            g <- GammaSet[k]
            
            Cindex.gamma.k <- rep(0, length = 5)
            
            # subset 1
            subset.train <- c(splt5$subset2, splt5$subset3, splt5$subset4, splt5$subset5)
            subset.test <- splt5$subset1
            svm.reg.k <- try(survivalsvm(formula = Surv(time, status) ~ ., data = RadC.train,
                                         subset = subset.train,
                                         type = "regression", gamma.mu = g,
                                         opt.meth = "quadprog", kernel = "lin_kernel"), 
                             silent = TRUE)
            if(!('try-error' %in% class(svm.reg.k))){
                pred.svm.reg.k <- predict(object = svm.reg.k, newdata = RadC.train, 
                                          subset = subset.test)
                Cindex.gamma.k[1] <- concordance.index(x = as.vector(-pred.svm.reg.k$predicted), 
                                                       surv.time = RadC.train$time[subset.test],
                                                       surv.event = RadC.train$status[subset.test])$c.index
            }else{
                print(paste0("Gamma = ", g, ", constraints are inconsistent, no solution!"))
            }
            
            # subset 2
            subset.train <- c(splt5$subset1, splt5$subset3, splt5$subset4, splt5$subset5)
            subset.test <- splt5$subset2
            svm.reg.k <- try(survivalsvm(formula = Surv(time, status) ~ ., data = RadC.train,
                                         subset = subset.train,
                                         type = "regression", gamma.mu = g,
                                         opt.meth = "quadprog", kernel = "lin_kernel"), 
                             silent = TRUE)
            if(!('try-error' %in% class(svm.reg.k))){
                pred.svm.reg.k <- predict(object = svm.reg.k, newdata = RadC.train, 
                                          subset = subset.test)
                Cindex.gamma.k[2] <- concordance.index(x = as.vector(-pred.svm.reg.k$predicted), 
                                                       surv.time = RadC.train$time[subset.test],
                                                       surv.event = RadC.train$status[subset.test])$c.index
            }else{
                print(paste0("Gamma = ", g, ", constraints are inconsistent, no solution!"))
            }
            
            # subset 3
            subset.train <- c(splt5$subset1, splt5$subset2, splt5$subset4, splt5$subset5)
            subset.test <- splt5$subset3
            svm.reg.k <- try(survivalsvm(formula = Surv(time, status) ~ ., data = RadC.train,
                                         subset = subset.train,
                                         type = "regression", gamma.mu = g,
                                         opt.meth = "quadprog", kernel = "lin_kernel"), 
                             silent = TRUE)
            if(!('try-error' %in% class(svm.reg.k))){
                pred.svm.reg.k <- predict(object = svm.reg.k, newdata = RadC.train, 
                                          subset = subset.test)
                Cindex.gamma.k[3] <- concordance.index(x = as.vector(-pred.svm.reg.k$predicted), 
                                                       surv.time = RadC.train$time[subset.test],
                                                       surv.event = RadC.train$status[subset.test])$c.index
            }else{
                print(paste0("Gamma = ", g, ", constraints are inconsistent, no solution!"))
            }
            
            # subset 4
            subset.train <- c(splt5$subset1, splt5$subset2, splt5$subset3, splt5$subset5)
            subset.test <- splt5$subset4
            svm.reg.k <- try(survivalsvm(formula = Surv(time, status) ~ ., data = RadC.train,
                                         subset = subset.train,
                                         type = "regression", gamma.mu = g,
                                         opt.meth = "quadprog", kernel = "lin_kernel"), 
                             silent = TRUE)
            if(!('try-error' %in% class(svm.reg.k))){
                pred.svm.reg.k <- predict(object = svm.reg.k, newdata = RadC.train, 
                                          subset = subset.test)
                Cindex.gamma.k[4] <- concordance.index(x = as.vector(-pred.svm.reg.k$predicted), 
                                                       surv.time = RadC.train$time[subset.test],
                                                       surv.event = RadC.train$status[subset.test])$c.index
            }else{
                print(paste0("Gamma = ", g, ", constraints are inconsistent, no solution!"))
            }
            
            # subset 5
            subset.train <- c(splt5$subset1, splt5$subset2, splt5$subset3, splt5$subset4)
            subset.test <- splt5$subset5
            svm.reg.k <- try(survivalsvm(formula = Surv(time, status) ~ ., data = RadC.train,
                                         subset = subset.train,
                                         type = "regression", gamma.mu = g,
                                         opt.meth = "quadprog", kernel = "lin_kernel"), 
                             silent = TRUE)
            if(!('try-error' %in% class(svm.reg.k))){
                pred.svm.reg.k <- predict(object = svm.reg.k, newdata = RadC.train, 
                                          subset = subset.test)
                Cindex.gamma.k[5] <- concordance.index(x = as.vector(-pred.svm.reg.k$predicted), 
                                                       surv.time = RadC.train$time[subset.test],
                                                       surv.event = RadC.train$status[subset.test])$c.index
            }else{
                print(paste0("Gamma = ", g, ", constraints are inconsistent, no solution!"))
            }
            
            # print(Cindex.gamma.k)
            Cindex.gamma[k] <- mean(Cindex.gamma.k)
        }
        
        
        Cindex.nFeats[j] <- max(Cindex.gamma)
        g <- GammaSet[which.max(Cindex.gamma)]
        GammaSel.nFeats[j] <- g
    }
    
    # Find the number of features (nFeats) with the maximum C-index
    numOfFeats[i] <- numOfFeatsSet[which.max(Cindex.nFeats)]
    GammaSel[i] <- GammaSel.nFeats[which.max(Cindex.nFeats)]
    
    Feats <- names(EBS.i)[1:numOfFeats[i]]
    g <- GammaSel[i]
    
    RadC.train <- data.frame(Rad.train[,Feats],
                             time = clinic.train$surv.clinical.Time.Months,
                             status = clinic.train$surv.clinical.Event)
    RadC.test <- data.frame(Rad.test[,Feats],
                            time = clinic.test$surv.clinical.Time.Months,
                            status = clinic.test$surv.clinical.Event)
    RadC.valid <- data.frame(Rad.valid[,Feats],
                             time = clinic.valid$surv.clinical.Time.Months,
                             status = clinic.valid$surv.clinical.Event)
    
    svm.reg <- try(survivalsvm(formula = Surv(time, status) ~ ., data = RadC.train,
                               subset = NULL,
                               type = "regression", gamma.mu = g,
                               opt.meth = "quadprog", kernel = "lin_kernel"), #quadprog
                   silent = TRUE)
    if(!('try-error' %in% class(svm.reg))){
        # training set
        lp.RS.train <- predict(object = svm.reg, newdata = RadC.train, 
                               subset = NULL)
        # Note that concordance_index_censored expects risk scores, therefore, we had to flip the sign of predictions.
        lp.RS.train <- as.vector(-lp.RS.train$predicted) #  flip sign to obtain risk scores
        
        # 5-year AUC
        perf.RS.train.5y <- tdrocc(x = lp.RS.train,
                                   surv.time = clinic.train$surv.clinical.Time.Months,
                                   surv.event = clinic.train$surv.clinical.Event,
                                   time = 5*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.train"] <- perf.RS.train.5y$AUC
        
        # 3-year AUC
        perf.RS.train.3y <- tdrocc(x = lp.RS.train,
                                   surv.time = clinic.train$surv.clinical.Time.Months,
                                   surv.event = clinic.train$surv.clinical.Event,
                                   time = 3*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.train"] <- perf.RS.train.3y$AUC
        
        # 5-year AUC
        perf.RS.train.1y <- tdrocc(x = lp.RS.train,
                                   surv.time = clinic.train$surv.clinical.Time.Months,
                                   surv.event = clinic.train$surv.clinical.Event,
                                   time = 1*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.train"] <- perf.RS.train.1y$AUC
        
        res.mat[i,"cindex.train"] <- concordance.index(lp.RS.train, 
                                                       clinic.train$surv.clinical.Time.Months,
                                                       clinic.train$surv.clinical.Event)$c.index
        # IAUC.train
        tt.train <- unique(sort(clinic.train$surv.clinical.Time.Months[clinic.train$surv.clinical.Event == 1]))
        mytdroc.train <- NULL
        for(i.tt in 1:length(tt.train)) {
            rr.train <- tdrocc(x=lp.RS.train, 
                               surv.time=clinic.train$surv.clinical.Time.Months, 
                               surv.event=clinic.train$surv.clinical.Event, 
                               time=tt.train[i.tt],
                               na.rm=TRUE, verbose=FALSE)
            mytdroc.train <- c(mytdroc.train, list(rr.train))
        }
        auc.train <- unlist(lapply(mytdroc.train, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.train"] <- iauc.comp(auc1=auc.train, auc2=auc.train, time=tt.train)$iauc1
        
        # Brier score.train
        bs.train <- data.frame(time = clinic.train$surv.clinical.Time.Months,
                               event = clinic.train$surv.clinical.Event,
                               score = lp.RS.train)
        res.mat[i,"bs.train"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.train, 
                               method="cox")$bsc.integrated
        
        # Log-rank.train x2
        RS.2cl.train <- rep(0, length = length(lp.RS.train))
        RS.2cl.train[which(lp.RS.train >= median(lp.RS.train))] <- 1
        df.train <- data.frame(bs.train, RS.2cl = RS.2cl.train)
        sdf <- survdiff(Surv(time,event)~RS.2cl, data=df.train)
        res.mat[i,"logrank.train"] <- sdf$chisq
        
        # HR.train
        lp.RS.train.sd <- (lp.RS.train - min(lp.RS.train))/(max(lp.RS.train) - min(lp.RS.train))
        df.train <- data.frame(df.train, score.sd = lp.RS.train.sd)
        res.mat[i,"HR.train"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                               data = df.train))$coefficients[2]
        
        
        # test set
        lp.RS.test <- predict(object = svm.reg, newdata = RadC.test, 
                              subset = NULL)
        lp.RS.test <- as.vector(-lp.RS.test$predicted)
        
        # 5-year AUC
        perf.RS.test.5y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 5*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.test"] <- perf.RS.test.5y$AUC
        
        # 3-year AUC
        perf.RS.test.3y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 3*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.test"] <- perf.RS.test.3y$AUC
        
        # 1-year AUC
        perf.RS.test.1y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 1*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.test"] <- perf.RS.test.1y$AUC
        
        res.mat[i,"cindex.test"] <- concordance.index(lp.RS.test, 
                                                      clinic.test$surv.clinical.Time.Months,
                                                      clinic.test$surv.clinical.Event)$c.index
        # IAUC.test
        tt.test <- unique(sort(clinic.test$surv.clinical.Time.Months[clinic.test$surv.clinical.Event == 1]))
        mytdroc.test <- NULL
        for(i.tt in 1:length(tt.test)) {
            rr.test <- tdrocc(x=lp.RS.test, 
                              surv.time=clinic.test$surv.clinical.Time.Months, 
                              surv.event=clinic.test$surv.clinical.Event, 
                              time=tt.test[i.tt],
                              na.rm=TRUE, verbose=FALSE)
            mytdroc.test <- c(mytdroc.test, list(rr.test))
        }
        auc.test <- unlist(lapply(mytdroc.test, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.test"] <- iauc.comp(auc1=auc.test, auc2=auc.test, time=tt.test)$iauc1
        
        # Brier score
        bs.test <- data.frame(time = clinic.test$surv.clinical.Time.Months,
                              event = clinic.test$surv.clinical.Event,
                              score = lp.RS.test)
        res.mat[i,"bs.test"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.test, 
                               method="cox")$bsc.integrated
        
        # Log-rank.test x2
        RS.2cl.test <- rep(0, length = length(lp.RS.test))
        RS.2cl.test[which(lp.RS.test >= median(lp.RS.train))] <- 1
        df.test <- data.frame(bs.test, RS.2cl = RS.2cl.test)
        sdf <- try(survdiff(Surv(time,event)~RS.2cl, data=df.test),
                   silent = TRUE)
        if(!('try-error' %in% class(sdf))){
            res.mat[i,"logrank.test"] <- sdf$chisq
        }else{
            print(paste0("Test set: Error in survdiff.fit, only 1 group!"))
        }
        
        
        # HR.test
        lp.RS.test.sd <- (lp.RS.test - min(lp.RS.test))/(max(lp.RS.test) - min(lp.RS.test))
        df.test <- data.frame(df.test, score.sd = lp.RS.test.sd)
        res.mat[i,"HR.test"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                              data = df.test))$coefficients[2]
        
        
        # valid set
        lp.RS.valid <- predict(object = svm.reg, newdata = RadC.valid, 
                               subset = NULL)
        lp.RS.valid <- as.vector(-lp.RS.valid$predicted)
        
        # 5-year AUC
        perf.RS.valid.5y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 5*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.valid"] <- perf.RS.valid.5y$AUC
        
        # 3-year AUC
        perf.RS.valid.3y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 3*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.valid"] <- perf.RS.valid.3y$AUC
        
        # 1-year AUC
        perf.RS.valid.1y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 1*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.valid"] <- perf.RS.valid.1y$AUC
        
        res.mat[i,"cindex.valid"] <- concordance.index(lp.RS.valid, 
                                                       clinic.valid$surv.clinical.Time.Months,
                                                       clinic.valid$surv.clinical.Event)$c.index
        # IAUC.valid
        tt.valid <- unique(sort(clinic.valid$surv.clinical.Time.Months[clinic.valid$surv.clinical.Event == 1]))
        mytdroc.valid <- NULL
        for(i.tt in 1:length(tt.valid)) {
            rr.valid <- tdrocc(x=lp.RS.valid, 
                               surv.time=clinic.valid$surv.clinical.Time.Months, 
                               surv.event=clinic.valid$surv.clinical.Event, 
                               time=tt.valid[i.tt],
                               na.rm=TRUE, verbose=FALSE)
            mytdroc.valid <- c(mytdroc.valid, list(rr.valid))
        }
        auc.valid <- unlist(lapply(mytdroc.valid, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.valid"] <- iauc.comp(auc1=auc.valid, auc2=auc.valid, time=tt.valid)$iauc1
        
        # Brier score
        bs.valid <- data.frame(time = clinic.valid$surv.clinical.Time.Months,
                               event = clinic.valid$surv.clinical.Event,
                               score = lp.RS.valid)
        res.mat[i,"bs.valid"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.valid, 
                               method="cox")$bsc.integrated
        
        # Log-rank.valid x2
        RS.2cl.valid <- rep(0, length = length(lp.RS.valid))
        RS.2cl.valid[which(lp.RS.valid >= median(lp.RS.train))] <- 1
        df.valid <- data.frame(bs.valid, RS.2cl = RS.2cl.valid)
        sdf <- try(survdiff(Surv(time,event)~RS.2cl, data=df.valid),
                   silent = TRUE)
        if(!('try-error' %in% class(sdf))){
            res.mat[i,"logrank.valid"] <- sdf$chisq
        }else{
            print(paste0("Valid set: Error in survdiff.fit, only 1 group!"))
        }
        
        # HR.valid
        lp.RS.valid.sd <- (lp.RS.valid - min(lp.RS.valid))/(max(lp.RS.valid) - min(lp.RS.valid))
        df.valid <- data.frame(df.valid, score.sd = lp.RS.valid.sd)
        res.mat[i,"HR.valid"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                               data = df.valid))$coefficients[2]
        
    }else{
        print(paste0("Gamma = ", g, ", No solution!"))
        numOfFailed <- numOfFailed + 1
    }
}

# Summarize average performance
meanRes <- rep(0, length = 24)
medianRes <- rep(0, length = 24)
sdRes <- rep(0, length = 24)
RSDRes <- rep(0, length = 24)
for(i in seq_len(ncol(res.mat))){
    meanRes[i] <- mean(res.mat[,i], na.rm = TRUE)
    medianRes[i] <- median(res.mat[,i], na.rm = TRUE)
    sdRes[i] <- sd(res.mat[,i], na.rm = TRUE)
    RSDRes[i] <- 100*sdRes[i]/meanRes[i]
}
res.mean <- data.frame(mean = meanRes,
                       median = medianRes,
                       sd = sdRes,
                       RSD = RSDRes)
rownames(res.mean) <- colnames(res.mat)

res.mRMR.svm <- list(res = res.mat,
                        res.mean = res.mean,
                        numOfFailed = numOfFailed,
                        numOfFeats = numOfFeats,
                        GammaSel = GammaSel)



# 5.11 RSF -----------
# load data 

# IBM.224.mat, Clinic.224.df, IBM.88.mat, Clinic.88.df
load(file = "./RData/NSCLC.IBM.224.88.clinic.224.88.RData")


# normalization
IBM.224.mat.sd <- scale(IBM.224.mat, center = TRUE, scale = TRUE)
IBM.88.mat.sd <- scale(IBM.88.mat, center = TRUE, scale = TRUE)

# Load predefined random train-test splits 
load(file = "./RData/rslist.NSCLC.IBM.224.88.clinic.224.88.RData")

# Load precomputed feature ranking based on mRMR-enhanced Borda score
load(file = "./RData/ls.mRMR.EBS.NSCLC.IBM.224.88.clinic.224.88.RData")
# ls.mRMR.EBS
topN <- 20

# repeat 100 times
N <- 100


# Number of features ranging from 5 up to 50, with an increment of 5 features (n= 5, 10, 15, 20, … , 50). 
numOfFeatsSet <- seq(from = 5, to = 50, by = 5)
numOfFeats <- rep(NA, length = N)  # Store the number of selected features

res.mat <- matrix(NA, nrow = N, ncol = 24)
colnames(res.mat) <- c("cindex.train", "AUC.1y.train", "AUC.3y.train",
                       "AUC.5y.train", "IAUC.train", "bs.train", "logrank.train", "HR.train",
                       "cindex.test",  "AUC.1y.test", "AUC.3y.test",  
                       "AUC.5y.test",  "IAUC.test", "bs.test", "logrank.test", "HR.test",
                       "cindex.valid", "AUC.1y.valid", "AUC.3y.valid", 
                       "AUC.5y.valid", "IAUC.valid", "bs.valid", "logrank.valid", "HR.valid")
numOfFailed <- 0

for(i in seq_len(N)){
    print(paste0("N: ",i, " ------------"))
    
    idx.train <- rslist[[i]]$idx.train
    idx.test <- rslist[[i]]$idx.test
    
    Rad.train <- IBM.224.mat.sd[idx.train,]
    Rad.test <- IBM.224.mat.sd[idx.test,]
    Rad.valid <- IBM.88.mat.sd
    
    clinic.train <- Clinic.224.df[idx.train,]
    clinic.test <- Clinic.224.df[idx.test,]
    clinic.valid <- Clinic.88.df
    
    # Load Cox P-values for the current training set
    EBS.i <- ls.mRMR.EBS[[i]]
    
    # Randomly split the training set into five subsets and use 5-fold CV to select the number of features (nFeats) that maximizes the C-index on the training-test sets
    splt5 <- mySplit(clinic.train)
    
    # Select the number of features
    Cindex.nFeats <- rep(0, length = length(numOfFeatsSet)) 
    for(j in seq_len(length(numOfFeatsSet))){
        print(paste0("NumOfFeats: ", numOfFeatsSet[j]))
        Feats <- names(EBS.i)[1:numOfFeatsSet[j]]
        
        Cindex.nFeats.j <- rep(0, length = 5)
        
        # subset 1
        subset.train <- c(splt5$subset2, splt5$subset3, splt5$subset4, splt5$subset5)
        subset.test <- splt5$subset1
        
        RadC.train.train <- data.frame(Rad.train[subset.train, Feats],
                                       time = clinic.train$surv.clinical.Time.Months[subset.train],
                                       status = clinic.train$surv.clinical.Event[subset.train])
        RadC.train.test <- data.frame(Rad.train[subset.test, Feats],
                                      time = clinic.train$surv.clinical.Time.Months[subset.test],
                                      status = clinic.train$surv.clinical.Event[subset.test])
        
        mod.j <- try(rfsrc(formula = Surv(time, status) ~ ., data = RadC.train.train, 
                           ntree=500), 
                     silent = TRUE)
        if(!('try-error' %in% class(mod.j))){
            lp.RS.train.test <- predict(object = mod.j, newdata = RadC.train.test)
            lp.RS.train.test <- lp.RS.train.test$predicted
            Cindex.nFeats.j[1] <- concordance.index(x = lp.RS.train.test, 
                                                    surv.time = RadC.train.test$time,
                                                    surv.event = RadC.train.test$status)$c.index
        }else{
            print(paste0("NumOfFeats: ", numOfFeatsSet[j], 
                         ", No solution!"))
        }
        
        # subset 2
        subset.train <- c(splt5$subset1, splt5$subset3, splt5$subset4, splt5$subset5)
        subset.test <- splt5$subset2
        
        RadC.train.train <- data.frame(Rad.train[subset.train, Feats],
                                       time = clinic.train$surv.clinical.Time.Months[subset.train],
                                       status = clinic.train$surv.clinical.Event[subset.train])
        RadC.train.test <- data.frame(Rad.train[subset.test, Feats],
                                      time = clinic.train$surv.clinical.Time.Months[subset.test],
                                      status = clinic.train$surv.clinical.Event[subset.test])
        
        mod.j <- try(rfsrc(formula = Surv(time, status) ~ ., data = RadC.train.train, 
                           ntree=500), 
                     silent = TRUE)
        if(!('try-error' %in% class(mod.j))){
            lp.RS.train.test <- predict(object = mod.j, newdata = RadC.train.test)
            lp.RS.train.test <- lp.RS.train.test$predicted
            Cindex.nFeats.j[2] <- concordance.index(x = lp.RS.train.test, 
                                                    surv.time = RadC.train.test$time,
                                                    surv.event = RadC.train.test$status)$c.index
        }else{
            print(paste0("NumOfFeats: ", numOfFeatsSet[j], 
                         ", No solution!"))
        }
        
        # subset 3
        subset.train <- c(splt5$subset1, splt5$subset2, splt5$subset4, splt5$subset5)
        subset.test <- splt5$subset3
        
        RadC.train.train <- data.frame(Rad.train[subset.train, Feats],
                                       time = clinic.train$surv.clinical.Time.Months[subset.train],
                                       status = clinic.train$surv.clinical.Event[subset.train])
        RadC.train.test <- data.frame(Rad.train[subset.test, Feats],
                                      time = clinic.train$surv.clinical.Time.Months[subset.test],
                                      status = clinic.train$surv.clinical.Event[subset.test])
        
        mod.j <- try(rfsrc(formula = Surv(time, status) ~ ., data = RadC.train.train, 
                           ntree=500), 
                     silent = TRUE)
        if(!('try-error' %in% class(mod.j))){
            lp.RS.train.test <- predict(object = mod.j, newdata = RadC.train.test)
            lp.RS.train.test <- lp.RS.train.test$predicted
            Cindex.nFeats.j[3] <- concordance.index(x = lp.RS.train.test, 
                                                    surv.time = RadC.train.test$time,
                                                    surv.event = RadC.train.test$status)$c.index
        }else{
            print(paste0("NumOfFeats: ", numOfFeatsSet[j], 
                         ", No solution!"))
        }
        
        # subset 4
        subset.train <- c(splt5$subset1, splt5$subset2, splt5$subset3, splt5$subset5)
        subset.test <- splt5$subset4
        
        RadC.train.train <- data.frame(Rad.train[subset.train, Feats],
                                       time = clinic.train$surv.clinical.Time.Months[subset.train],
                                       status = clinic.train$surv.clinical.Event[subset.train])
        RadC.train.test <- data.frame(Rad.train[subset.test, Feats],
                                      time = clinic.train$surv.clinical.Time.Months[subset.test],
                                      status = clinic.train$surv.clinical.Event[subset.test])
        
        mod.j <- try(rfsrc(formula = Surv(time, status) ~ ., data = RadC.train.train, 
                           ntree=500), 
                     silent = TRUE)
        if(!('try-error' %in% class(mod.j))){
            lp.RS.train.test <- predict(object = mod.j, newdata = RadC.train.test)
            lp.RS.train.test <- lp.RS.train.test$predicted
            Cindex.nFeats.j[4] <- concordance.index(x = lp.RS.train.test, 
                                                    surv.time = RadC.train.test$time,
                                                    surv.event = RadC.train.test$status)$c.index
        }else{
            print(paste0("NumOfFeats: ", numOfFeatsSet[j], 
                         ", No solution!"))
        }
        
        # subset 5
        subset.train <- c(splt5$subset1, splt5$subset2, splt5$subset3, splt5$subset4)
        subset.test <- splt5$subset5
        
        RadC.train.train <- data.frame(Rad.train[subset.train, Feats],
                                       time = clinic.train$surv.clinical.Time.Months[subset.train],
                                       status = clinic.train$surv.clinical.Event[subset.train])
        RadC.train.test <- data.frame(Rad.train[subset.test, Feats],
                                      time = clinic.train$surv.clinical.Time.Months[subset.test],
                                      status = clinic.train$surv.clinical.Event[subset.test])
        
        mod.j <- try(rfsrc(formula = Surv(time, status) ~ ., data = RadC.train.train, 
                           ntree=500), 
                     silent = TRUE)
        if(!('try-error' %in% class(mod.j))){
            lp.RS.train.test <- predict(object = mod.j, newdata = RadC.train.test)
            lp.RS.train.test <- lp.RS.train.test$predicted
            Cindex.nFeats.j[5] <- concordance.index(x = lp.RS.train.test, 
                                                    surv.time = RadC.train.test$time,
                                                    surv.event = RadC.train.test$status)$c.index
        }else{
            print(paste0("NumOfFeats: ", numOfFeatsSet[j], 
                         ", No solution!"))
        }
        
        Cindex.nFeats[j] <- mean(Cindex.nFeats.j)
    }
    
    # Find the number of features (nFeats) with the maximum C-index
    numOfFeats[i] <- numOfFeatsSet[which.max(Cindex.nFeats)]
    Feats <- names(EBS.i)[1:numOfFeats[i]]
    
    # Build the model and make predictions using features with the maximum C-index
    RadC.train <- data.frame(Rad.train[,Feats],
                             time = clinic.train$surv.clinical.Time.Months,
                             status = clinic.train$surv.clinical.Event)
    RadC.test <- data.frame(Rad.test[,Feats],
                            time = clinic.test$surv.clinical.Time.Months,
                            status = clinic.test$surv.clinical.Event)
    RadC.valid <- data.frame(Rad.valid[,Feats],
                             time = clinic.valid$surv.clinical.Time.Months,
                             status = clinic.valid$surv.clinical.Event)
    
    mod.i <- try(rfsrc(formula = Surv(time, status) ~ ., data = RadC.train, 
                       ntree=500), 
                 silent = TRUE)
    if(!('try-error' %in% class(mod.i))){
        # training set
        lp.RS.train <- predict(object = mod.i, newdata = RadC.train)
        lp.RS.train <- lp.RS.train$predicted
        
        # 5-year AUC
        perf.RS.train.5y <- tdrocc(x = lp.RS.train,
                                   surv.time = clinic.train$surv.clinical.Time.Months,
                                   surv.event = clinic.train$surv.clinical.Event,
                                   time = 5*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.train"] <- perf.RS.train.5y$AUC
        
        # 3-year AUC
        perf.RS.train.3y <- tdrocc(x = lp.RS.train,
                                   surv.time = clinic.train$surv.clinical.Time.Months,
                                   surv.event = clinic.train$surv.clinical.Event,
                                   time = 3*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.train"] <- perf.RS.train.3y$AUC
        
        # 5-year AUC
        perf.RS.train.1y <- tdrocc(x = lp.RS.train,
                                   surv.time = clinic.train$surv.clinical.Time.Months,
                                   surv.event = clinic.train$surv.clinical.Event,
                                   time = 1*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.train"] <- perf.RS.train.1y$AUC
        
        res.mat[i,"cindex.train"] <- concordance.index(lp.RS.train, 
                                                       clinic.train$surv.clinical.Time.Months,
                                                       clinic.train$surv.clinical.Event)$c.index
        # IAUC.train
        tt.train <- unique(sort(clinic.train$surv.clinical.Time.Months[clinic.train$surv.clinical.Event == 1]))
        mytdroc.train <- NULL
        for(i.tt in 1:length(tt.train)) {
            rr.train <- tdrocc(x=lp.RS.train, 
                               surv.time=clinic.train$surv.clinical.Time.Months, 
                               surv.event=clinic.train$surv.clinical.Event, 
                               time=tt.train[i.tt],
                               na.rm=TRUE, verbose=FALSE)
            mytdroc.train <- c(mytdroc.train, list(rr.train))
        }
        auc.train <- unlist(lapply(mytdroc.train, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.train"] <- iauc.comp(auc1=auc.train, auc2=auc.train, time=tt.train)$iauc1
        
        # Brier score.train
        bs.train <- data.frame(time = clinic.train$surv.clinical.Time.Months,
                               event = clinic.train$surv.clinical.Event,
                               score = lp.RS.train)
        res.mat[i,"bs.train"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.train, 
                               method="cox")$bsc.integrated
        
        # Log-rank.train x2
        RS.2cl.train <- rep(0, length = length(lp.RS.train))
        RS.2cl.train[which(lp.RS.train >= median(lp.RS.train))] <- 1
        df.train <- data.frame(bs.train, RS.2cl = RS.2cl.train)
        sdf <- survdiff(Surv(time,event)~RS.2cl, data=df.train)
        res.mat[i,"logrank.train"] <- sdf$chisq
        
        # HR.train
        lp.RS.train.sd <- (lp.RS.train - min(lp.RS.train))/(max(lp.RS.train) - min(lp.RS.train))
        df.train <- data.frame(df.train, score.sd = lp.RS.train.sd)
        res.mat[i,"HR.train"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                               data = df.train))$coefficients[2]
        
        # test set
        lp.RS.test <- predict(object = mod.i, newdata = RadC.test)
        lp.RS.test <- lp.RS.test$predicted
        
        # 5-year AUC
        perf.RS.test.5y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 5*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.test"] <- perf.RS.test.5y$AUC
        
        # 3-year AUC
        perf.RS.test.3y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 3*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.test"] <- perf.RS.test.3y$AUC
        
        # 1-year AUC
        perf.RS.test.1y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 1*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.test"] <- perf.RS.test.1y$AUC
        
        res.mat[i,"cindex.test"] <- concordance.index(lp.RS.test, 
                                                      clinic.test$surv.clinical.Time.Months,
                                                      clinic.test$surv.clinical.Event)$c.index
        # IAUC.test
        tt.test <- unique(sort(clinic.test$surv.clinical.Time.Months[clinic.test$surv.clinical.Event == 1]))
        mytdroc.test <- NULL
        for(i.tt in 1:length(tt.test)) {
            rr.test <- tdrocc(x=lp.RS.test, 
                              surv.time=clinic.test$surv.clinical.Time.Months, 
                              surv.event=clinic.test$surv.clinical.Event, 
                              time=tt.test[i.tt],
                              na.rm=TRUE, verbose=FALSE)
            mytdroc.test <- c(mytdroc.test, list(rr.test))
        }
        auc.test <- unlist(lapply(mytdroc.test, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.test"] <- iauc.comp(auc1=auc.test, auc2=auc.test, time=tt.test)$iauc1
        
        # Brier score
        bs.test <- data.frame(time = clinic.test$surv.clinical.Time.Months,
                              event = clinic.test$surv.clinical.Event,
                              score = lp.RS.test)
        res.mat[i,"bs.test"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.test, 
                               method="cox")$bsc.integrated
        
        # Log-rank.test x2
        RS.2cl.test <- rep(0, length = length(lp.RS.test))
        RS.2cl.test[which(lp.RS.test >= median(lp.RS.train))] <- 1
        df.test <- data.frame(bs.test, RS.2cl = RS.2cl.test)
        sdf <- try(survdiff(Surv(time,event)~RS.2cl, data=df.test),
                   silent = TRUE)
        if(!('try-error' %in% class(sdf))){
            res.mat[i,"logrank.test"] <- sdf$chisq
        }else{
            print(paste0("Test set: Error in survdiff.fit, only 1 group!"))
        }
        
        
        # HR.test
        lp.RS.test.sd <- (lp.RS.test - min(lp.RS.test))/(max(lp.RS.test) - min(lp.RS.test))
        df.test <- data.frame(df.test, score.sd = lp.RS.test.sd)
        res.mat[i,"HR.test"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                              data = df.test))$coefficients[2]
        
        
        # valid set
        lp.RS.valid <- predict(object = mod.i, newdata = RadC.valid)
        lp.RS.valid <- lp.RS.valid$predicted
        
        # 5-year AUC
        perf.RS.valid.5y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 5*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.valid"] <- perf.RS.valid.5y$AUC
        
        # 3-year AUC
        perf.RS.valid.3y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 3*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.valid"] <- perf.RS.valid.3y$AUC
        
        # 1-year AUC
        perf.RS.valid.1y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 1*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.valid"] <- perf.RS.valid.1y$AUC
        
        res.mat[i,"cindex.valid"] <- concordance.index(lp.RS.valid, 
                                                       clinic.valid$surv.clinical.Time.Months,
                                                       clinic.valid$surv.clinical.Event)$c.index
        # IAUC.valid
        tt.valid <- unique(sort(clinic.valid$surv.clinical.Time.Months[clinic.valid$surv.clinical.Event == 1]))
        mytdroc.valid <- NULL
        for(i.tt in 1:length(tt.valid)) {
            rr.valid <- tdrocc(x=lp.RS.valid, 
                               surv.time=clinic.valid$surv.clinical.Time.Months, 
                               surv.event=clinic.valid$surv.clinical.Event, 
                               time=tt.valid[i.tt],
                               na.rm=TRUE, verbose=FALSE)
            mytdroc.valid <- c(mytdroc.valid, list(rr.valid))
        }
        auc.valid <- unlist(lapply(mytdroc.valid, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.valid"] <- iauc.comp(auc1=auc.valid, auc2=auc.valid, time=tt.valid)$iauc1
        
        # Brier score
        bs.valid <- data.frame(time = clinic.valid$surv.clinical.Time.Months,
                               event = clinic.valid$surv.clinical.Event,
                               score = lp.RS.valid)
        res.mat[i,"bs.valid"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.valid, 
                               method="cox")$bsc.integrated
        
        # Log-rank.valid x2
        RS.2cl.valid <- rep(0, length = length(lp.RS.valid))
        RS.2cl.valid[which(lp.RS.valid >= median(lp.RS.train))] <- 1
        df.valid <- data.frame(bs.valid, RS.2cl = RS.2cl.valid)
        sdf <- try(survdiff(Surv(time,event)~RS.2cl, data=df.valid),
                   silent = TRUE)
        if(!('try-error' %in% class(sdf))){
            res.mat[i,"logrank.valid"] <- sdf$chisq
        }else{
            print(paste0("Valid set: Error in survdiff.fit, only 1 group!"))
        }
        
        # HR.valid
        lp.RS.valid.sd <- (lp.RS.valid - min(lp.RS.valid))/(max(lp.RS.valid) - min(lp.RS.valid))
        df.valid <- data.frame(df.valid, score.sd = lp.RS.valid.sd)
        res.mat[i,"HR.valid"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                               data = df.valid))$coefficients[2]
    }else{
        print(paste0("NumOfFeats: ", numOfFeats[i], 
                     ", No solution!"))
        numOfFailed <- numOfFailed + 1
    }
}

# Summarize average performance
meanRes <- rep(0, length = 24)
medianRes <- rep(0, length = 24)
sdRes <- rep(0, length = 24)
RSDRes <- rep(0, length = 24)
for(i in seq_len(ncol(res.mat))){
    meanRes[i] <- mean(res.mat[,i], na.rm = TRUE)
    medianRes[i] <- median(res.mat[,i], na.rm = TRUE)
    sdRes[i] <- sd(res.mat[,i], na.rm = TRUE)
    RSDRes[i] <- 100*sdRes[i]/meanRes[i]
}
res.mean <- data.frame(mean = meanRes,
                       median = medianRes,
                       sd = sdRes,
                       RSD = RSDRes)
rownames(res.mean) <- colnames(res.mat)

res.mRMR.RSF <- list(res = res.mat,
                        res.mean = res.mean,
                        numOfFailed = numOfFailed,
                        numOfFeats = numOfFeats)



# 5.12 DeepSurv ---------------
# 5.12.1 Hyperparameter tuning for DeepSurv---------------
# load data 

# IBM.224.mat, Clinic.224.df, IBM.88.mat, Clinic.88.df
load(file = "./RData/NSCLC.IBM.224.88.clinic.224.88.RData")


# normalization
IBM.224.mat.sd <- scale(IBM.224.mat, center = TRUE, scale = TRUE)
IBM.88.mat.sd <- scale(IBM.88.mat, center = TRUE, scale = TRUE)

# mRMR Enhanced Borda Score Whole Dataset
library("mRMRe")

N <- 100

# Bootstrapping, n = 100
ls.EBS.tmp <- vector(mode = "list", length = 100)
for(bt in seq_len(100)){
    print(bt)
    # bootstrap
    idx.bt <- unique(sample(x = nrow(IBM.224.mat.sd), size = nrow(IBM.224.mat.sd), 
                            replace = TRUE))
    IBM.bt <- IBM.224.mat.sd[idx.bt,]
    clinic.bt <- Clinic.224.df[idx.bt, ]
    
    RadC <- data.frame("surv" = Surv(time = clinic.bt$surv.clinical.Time.Months,
                                     event = clinic.bt$surv.clinical.Event),
                       IBM.bt)
    dd <- mRMR.data(data = RadC)
    
    # 20 features
    res.mRMR <- mRMR.classic(data = dd, target_indices = c(1),
                             feature_count = 20)
    Feats.20 <- res.mRMR@feature_names[res.mRMR@filters$`1`[,1]]
    
    ls.EBS.tmp[[bt]] <- Feats.20
}

# 对每个bootstrap, 取top 20 best features
Feats <- c()
for(bt in seq_len(100)){
    Feats.bt <- ls.EBS.tmp[[bt]]
    Feats <- append(Feats, Feats.bt)
}
Feats.unique <- unique(Feats)

# calculate enhanced Borda score
Rank.mat <- matrix(NA, nrow = length(Feats.unique), ncol = 100)
rownames(Rank.mat) <- Feats.unique
Feats.occ <- rep(0, length = length(Feats.unique))
names(Feats.occ) <- Feats.unique
for(bt in seq_len(100)){
    Feats.bt <- ls.EBS.tmp[[bt]]
    
    for(j in seq_len(length(Feats.unique))){
        if(Feats.unique[j] %in% Feats.bt){
            Feats.occ[j] <- Feats.occ[j] + 1
        }
    }
    
    for(k in seq_len(length(Feats.bt))){
        Rank.mat[Feats.bt[k], bt] <- k
    }
}

# enhanced Borda score
Feats.EBS <- rep(0, length = length(Feats.unique))
names(Feats.EBS) <- Feats.unique
for(j in seq_len(length(Feats.unique))){
    R <- 0
    for(k in seq_len(100)){
        if(!is.na(Rank.mat[j,k])){
            # print(k)
            # print(Rank.mat[j,k])
            R <- R + sqrt(Rank.mat[j,k])
            # print(R)
        }
    }
    Feats.EBS[j] <- R/(Feats.occ[j]^2)
}
mRMR.EBS <- sort(Feats.EBS)

save(mRMR.EBS,
     file = "./RData/mRMR.EBS.NSCLC.IBM.224.88.clinic.224.88.RData")


load(file = "./RData/mRMR.EBS.NSCLC.IBM.224.88.clinic.224.88.RData")
topN <- 106
Feats <- names(mRMR.EBS)[1:topN]

library(reticulate)
library(survivalmodels)
library(mlr3)
library(mlr3proba)
library(paradox) # Define and Work with Parameter Spaces for Complex Algorithms
library(mlr3tuning)
library(mlr3extralearners)## learners are stored in mlr3extralearners

# dataset
RadC.224 <- data.frame(IBM.224.mat.sd[,Feats],
                       time = Clinic.224.df$surv.clinical.Time.Months,
                       status = Clinic.224.df$surv.clinical.Event)

## create our own task
task.NSCLC <- TaskSurv$new(id = "NSCLC", # task id
                           backend = RadC.224,  # data, data.table or data.frame
                           time = "time",  # Name of the column for event time
                           event = "status") # Name of the column giving the event indicator
# "0"/FALSE means alive (no event), "1"/TRUE means dead (event)

# Hyperparameter tuning
lrn.deepsurv <- lrn("surv.deepsurv", 
                    frac = 0.3,  # Fraction of data to use for validation dataset
                    early_stopping = TRUE, 
                    epochs = 500, 
                    batch_norm = TRUE # batch normalisation
                    # optimizer = "adam",
)

# lrn.deepsurv$param_set

search_space <- ps(
    ## p_dbl for numeric valued parameters
    activation = p_fct(levels = c("relu", "selu")),  
    dropout = p_dbl(lower = 0, upper = 0.8),  # 
    weight_decay = p_dbl(lower = 0, upper = 0.5), # Passed to all methods except rprop and sparse_adam
    # learning_rate = p_dbl(lower = 1e-4, upper = 1),
    learning_rate = p_dbl(lower = 1, upper = 9, trafo = function(x) exp(x)/exp(10)),
    optimizer = p_fct(levels = c("adam", "sgd")),
    # momentum = p_dbl(lower = 0, upper = 1), 
    
    ## p_int for integer valued parameters
    nodes = p_int(lower = 2, upper = 7), # the number of nodes in a layer
    k = p_int(lower = 1, upper = 4),  # the number of layers
    .extra_trafo = function(x, param_set) {
        # x$num_nodes = c()
        # n_layers = x$k
        # for(n_l in seq_len(n_layers)){
        #     x$num_nodes = c(x$num_nodes, sample(c(4,8,16,24,32,64),1))
        # }
        x$num_nodes = rep(2^(x$nodes), x$k)
        x$nodes = x$k = NULL
        # x$k = NULL
        if(x$optimizer == "sgd"){
            x$momentum = 0.8 #runif(1, 0.8,0.95)
        }
        return(x)
    }
)

## select holdout as the resampling strategy
resampling <- rsmp("cv", folds = 3)
resampling <- rsmp("repeated_cv", repeats = 5, folds = 3)

# hout = rsmp("holdout")
measure = msr("surv.cindex")

library("mlr3tuning")
# Terminate after a given time (TerminatorClockTime).
# Terminate after a given number of iterations (TerminatorEvals).
# Terminate after a specific performance has been reached (TerminatorPerfReached).
# Terminate when tuning does find a better configuration for a given number of iterations (TerminatorStagnation).
# A combination of the above in an ALL or ANY fashion (TerminatorCombo).
evals20 = trm("evals", n_evals = 2)
trm10 = trm("stagnation", iters = 3000, threshold = 1e-5)
trm.comb = trm("combo",
               list(
                   trm("clock_time", stop_time = Sys.time() + 72000),
                   trm("stagnation", iters = 6000, threshold = 1e-5)
               ), any = TRUE)

instance = TuningInstanceSingleCrit$new(
    task = task.NSCLC,
    learner = lrn.deepsurv,
    resampling = resampling,
    measure = measure,
    search_space = search_space,
    terminator = trm.comb#evals20#
)
instance

tuner = tnr("random_search", batch_size = 5)  # Maximum number of points to try in a batch.
tuner = tnr("grid_search",
            param_resolutions = c("dropout" = 20,
                                  "learning_rate" = 20,
                                  "weight_decay" = 10),
            batch_size = 5)  # Maximum number of points to try in a batch.
tuner$optimize(instance)
instance$result_learner_param_vals   # Optimal parameters
instance$result_y   # Optimal results
# as.data.table(instance$archive)  # All results
# instance$archive$benchmark_result


lrn.deepsurv$param_set$values = instance$result_learner_param_vals  # select optimal parameters

save(lrn.deepsurv, file = "./RData/lrn.deepsurv.mRMR.NSCLC.IBM.224.88.clinic.224.88.RData")


