        res.mat[i,"cindex.valid"] <- concordance.index(lp.RS.valid, 
                                                       clinic.valid$surv.clinical.Time.Months,
                                                       clinic.valid$surv.clinical.Event)$c.index
        # IAUC.valid
        tt.valid <- unique(sort(clinic.valid$surv.clinical.Time.Months[clinic.valid$surv.clinical.Event == 1]))
        mytdroc.valid <- NULL
        for(i.tt in 1:length(tt.valid)) {
            rr.valid <- tdrocc(x=lp.RS.valid, 
                               surv.time=clinic.valid$surv.clinical.Time.Months, 
                               surv.event=clinic.valid$surv.clinical.Event, 
                               time=tt.valid[i.tt],
                               na.rm=TRUE, verbose=FALSE)
            mytdroc.valid <- c(mytdroc.valid, list(rr.valid))
        }
        auc.valid <- unlist(lapply(mytdroc.valid, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.valid"] <- iauc.comp(auc1=auc.valid, auc2=auc.valid, time=tt.valid)$iauc1
        
        # Brier score
        bs.valid <- data.frame(time = clinic.valid$surv.clinical.Time.Months,
                               event = clinic.valid$surv.clinical.Event,
                               score = lp.RS.valid)
        res.mat[i,"bs.valid"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.valid, 
                               method="cox")$bsc.integrated
        
        # Log-rank.valid x2
        RS.2cl.valid <- rep(0, length = length(lp.RS.valid))
        RS.2cl.valid[which(lp.RS.valid >= median(lp.RS.train))] <- 1
        df.valid <- data.frame(bs.valid, RS.2cl = RS.2cl.valid)
        sdf <- try(survdiff(Surv(time,event)~RS.2cl, data=df.valid),
                   silent = TRUE)
        if(!('try-error' %in% class(sdf))){
            res.mat[i,"logrank.valid"] <- sdf$chisq
        }else{
            print(paste0("Valid set: Error in survdiff.fit, only 1 group!"))
        }
        
        # HR.valid
