# load data 

# IBM.224.mat, Clinic.224.df, IBM.88.mat, Clinic.88.df
load(file = "./RData/NSCLC.IBM.224.88.clinic.224.88.RData")


# normalization
IBM.224.mat.sd <- scale(IBM.224.mat, center = TRUE, scale = TRUE)
IBM.88.mat.sd <- scale(IBM.88.mat, center = TRUE, scale = TRUE)

# Load predefined random train-test splits 
load(file = "./RData/rslist.NSCLC.IBM.224.88.clinic.224.88.RData")

# Load precomputed feature ranking based on md-enhanced Borda score
load(file = "./RData/ls.md.EBS.NSCLC.IBM.224.88.clinic.224.88.RData")
# ls.md.EBS
topN <- 20

# repeat 100 times
N <- 100


# Number of features ranging from 5 up to 50, with an increment of 5 features (n= 5, 10, 15, 20, … , 50). 
numOfFeatsSet <- seq(from = 5, to = 50, by = 5)
numOfFeats <- rep(NA, length = N)  # Store the number of selected features

res.mat <- matrix(NA, nrow = N, ncol = 24)
colnames(res.mat) <- c("cindex.train", "AUC.1y.train", "AUC.3y.train",
                       "AUC.5y.train", "IAUC.train", "bs.train", "logrank.train", "HR.train",
                       "cindex.test",  "AUC.1y.test", "AUC.3y.test",  
                       "AUC.5y.test",  "IAUC.test", "bs.test", "logrank.test", "HR.test",
                       "cindex.valid", "AUC.1y.valid", "AUC.3y.valid", 
                       "AUC.5y.valid", "IAUC.valid", "bs.valid", "logrank.valid", "HR.valid")
numOfFailed <- 0

for(i in seq_len(N)){
    print(paste0("N: ",i, " ------------"))
    
    idx.train <- rslist[[i]]$idx.train
    idx.test <- rslist[[i]]$idx.test
    
    Rad.train <- IBM.224.mat.sd[idx.train,]
    Rad.test <- IBM.224.mat.sd[idx.test,]
    Rad.valid <- IBM.88.mat.sd
    
    clinic.train <- Clinic.224.df[idx.train,]
    clinic.test <- Clinic.224.df[idx.test,]
    clinic.valid <- Clinic.88.df
    
    # Load Cox P-values for the current training set
    EBS.i <- ls.md.EBS[[i]]
    
    # Randomly split the training set into five subsets and use 5-fold CV to select the number of features (nFeats) that maximizes the C-index on the training-test sets
    splt5 <- mySplit(clinic.train)
    
    # Select the number of features
    Cindex.nFeats <- rep(0, length = length(numOfFeatsSet)) 
    for(j in seq_len(length(numOfFeatsSet))){
        print(paste0("NumOfFeats: ", numOfFeatsSet[j]))
        Feats <- names(EBS.i)[1:numOfFeatsSet[j]]
        
        Cindex.nFeats.j <- rep(0, length = 5)
        
        # subset 1
        subset.train <- c(splt5$subset2, splt5$subset3, splt5$subset4, splt5$subset5)
        subset.test <- splt5$subset1
        
        RadC.train.train <- data.frame(Rad.train[subset.train, Feats],
                                       time = clinic.train$surv.clinical.Time.Months[subset.train],
                                       status = clinic.train$surv.clinical.Event[subset.train])
        RadC.train.test <- data.frame(Rad.train[subset.test, Feats],
                                      time = clinic.train$surv.clinical.Time.Months[subset.test],
                                      status = clinic.train$surv.clinical.Event[subset.test])
        
        mod.j <- try(rfsrc(formula = Surv(time, status) ~ ., data = RadC.train.train, 
                           ntree=500), 
                     silent = TRUE)
        if(!('try-error' %in% class(mod.j))){
            lp.RS.train.test <- predict(object = mod.j, newdata = RadC.train.test)
            lp.RS.train.test <- lp.RS.train.test$predicted
            Cindex.nFeats.j[1] <- concordance.index(x = lp.RS.train.test, 
                                                    surv.time = RadC.train.test$time,
                                                    surv.event = RadC.train.test$status)$c.index
        }else{
            print(paste0("NumOfFeats: ", numOfFeatsSet[j], 
                         ", No solution!"))
        }
        
        # subset 2
        subset.train <- c(splt5$subset1, splt5$subset3, splt5$subset4, splt5$subset5)
        subset.test <- splt5$subset2
        
        RadC.train.train <- data.frame(Rad.train[subset.train, Feats],
