#****************************** 8: HC ****************************** -------------
# 8.1：Lasso-Cox -----------
# load data 

# IBM.224.mat, Clinic.224.df, IBM.88.mat, Clinic.88.df
load(file = "./RData/NSCLC.IBM.224.88.clinic.224.88.RData")


# load HC features
load(file = "./RData/NSCLC.IBM.hc.224.88.clinic.224.88.RData")
# IBM.224.mat.sd.hc, IBM.88.mat.sd.hc

# normalization
IBM.224.mat.sd <- scale(IBM.224.mat.sd.hc, center = TRUE, scale = TRUE)
IBM.88.mat.sd <- scale(IBM.88.mat.sd.hc, center = TRUE, scale = TRUE)

# Load predefined random train-test splits 
load(file = "./RData/rslist.NSCLC.IBM.224.88.clinic.224.88.RData")

#  HC+Feature extraction 
# if (!require("BiocManager", quietly = TRUE))
#     install.packages("BiocManager") 
# BiocManager::install("bioDist")

library("bioDist")

d <- IBM.224.mat.sd
d.spearman <- spearman.dist(t(d))
hc <- hclust(d.spearman, method = "complete")
cutoff <- hc$height[which(hc$height > 0.1)[1]]  # height阈值，用于cut trees Spearman corr > 0.9
grp <- cutree(hc, h = cutoff)  # 按高度cut tree， cut为155 clusters
numOfCls <- length(table(grp)) # number of clusters

# 构造meta-feature matrix calculated by averaging over all features within the cluster
IBM.224.mat.sd.hc <- matrix(NA, nrow = nrow(IBM.224.mat.sd), ncol = numOfCls)
rownames(IBM.224.mat.sd.hc) <- rownames(IBM.224.mat.sd)
colnames(IBM.224.mat.sd.hc) <- paste0("HC",1:numOfCls)
IBM.88.mat.sd.hc  <- matrix(NA, nrow = nrow(IBM.88.mat.sd), ncol = numOfCls)
rownames(IBM.88.mat.sd.hc) <- rownames(IBM.88.mat.sd)
colnames(IBM.88.mat.sd.hc) <- paste0("HC",1:numOfCls)

for(i in seq_len(numOfCls)){
    Feats.i <- names(grp)[which(grp == i)]
    if(length(Feats.i) == 1){   # 若该cluster只有1个Feature
        IBM.224.mat.sd.hc[,i] <- IBM.224.mat.sd[,Feats.i]
        IBM.88.mat.sd.hc[,i] <- IBM.88.mat.sd[,Feats.i]
    }else{
        Featvector.224 <- IBM.224.mat.sd[,Feats.i[1]]
        Featvector.88 <- IBM.88.mat.sd[,Feats.i[1]]
        for(j in 2:length(Feats.i)){
            cor.1.j <- cor(x = IBM.224.mat.sd[,Feats.i[1]],
                           y = IBM.224.mat.sd[,Feats.i[j]],
                           method = "spearman")
            print(cor.1.j)
            if(cor.1.j > 0){
                Featvector.224 <- Featvector.224 + IBM.224.mat.sd[,Feats.i[j]]
                Featvector.88 <- Featvector.88 + IBM.88.mat.sd[,Feats.i[j]]
            }else{  # Negatively correlated features were invered before averaging
                Featvector.224 <- Featvector.224 - IBM.224.mat.sd[,Feats.i[j]]
                Featvector.88 <- Featvector.88 - IBM.88.mat.sd[,Feats.i[j]]
            }
        }
        # 取平均
        IBM.224.mat.sd.hc[,i] <- Featvector.224 / length(Feats.i)
        IBM.88.mat.sd.hc[,i] <- Featvector.88 / length(Feats.i)
    }
}

save(IBM.224.mat.sd.hc, IBM.88.mat.sd.hc,
     file = "./RData/NSCLC.IBM.hc.224.88.clinic.224.88.RData")

# HC+Spearman 
load(file = "./RData/NSCLC.IBM.hc.224.88.clinic.224.88.RData")

N <- 100
ls.HC.Spearman.EBS <- vector(mode = "list", length = N)
for(i in seq_len(N)){
    print(paste0("i: ", i, "----------"))
    
    idx.train <- rslist[[i]]$idx.train
    
    IBM.train <- IBM.224.mat.sd.hc[idx.train,]
    clinic.train <- Clinic.224.df[idx.train,]
    
    # Bootstrapping, n = 100
    ls.HC.Spearman.EBS.tmp <- vector(mode = "list", length = 100)
    for(bt in seq_len(100)){
        print(bt)
        # bootstrap
        idx.bt <- unique(sample(x = nrow(IBM.train), size = nrow(IBM.train), 
                                replace = TRUE))
        IBM.train.bt <- IBM.train[idx.bt,]
        clinic.train.bt <- clinic.train[idx.bt, ]
        
        idx.event <- which(clinic.train.bt$surv.clinical.Event == 1)
        IBM.train.bt.event <- IBM.train.bt[idx.event, ]
        clinic.train.bt.event <- clinic.train.bt[idx.event, ]
        
        Spearman.bt <- rep(NA, length = ncol(IBM.train.bt.event))
        names(Spearman.bt) <- colnames(IBM.train.bt.event)
        for(j in seq_len(ncol(IBM.train.bt.event))){
            Spearman.bt[j] <- cor(x = IBM.train.bt.event[,j], 
                                  y = clinic.train.bt.event$surv.clinical.Time.Months,
                                  method = "spearman")
        }
        
        Spearman.bt.sort <- sort(abs(Spearman.bt), decreasing = TRUE)
        ls.HC.Spearman.EBS.tmp[[bt]] <- names(Spearman.bt.sort)[1:20]
        
    }
    
    # 对每个bootstrap, 取top 20 best features
    Feats.Spearman <- c()
    for(bt in seq_len(100)){
        Spearman.bt <- ls.HC.Spearman.EBS.tmp[[bt]]
        Feats.Spearman <- append(Feats.Spearman, Spearman.bt)
    }
    Feats.Spearman.unique <- unique(Feats.Spearman)
    
    # calculate enhanced Borda score
    Rank.Spearman.mat <- matrix(NA, nrow = length(Feats.Spearman.unique), ncol = 100)
    rownames(Rank.Spearman.mat) <- Feats.Spearman.unique
    Feats.Spearman.occ <- rep(0, length = length(Feats.Spearman.unique))
    names(Feats.Spearman.occ) <- Feats.Spearman.unique
    
    for(bt in seq_len(100)){
        Feats.Spearman.bt <- ls.HC.Spearman.EBS.tmp[[bt]]
        
        for(j in seq_len(length(Feats.Spearman.unique))){
            if(Feats.Spearman.unique[j] %in% Feats.Spearman.bt){
                Feats.Spearman.occ[j] <- Feats.Spearman.occ[j] + 1
            }
        }
        
        for(k in seq_len(length(Feats.Spearman.bt))){
            Rank.Spearman.mat[Feats.Spearman.bt[k], bt] <- k
        }
    }
    
    # enhanced Borda score
    Feats.Spearman.EBS <- rep(0, length = length(Feats.Spearman.unique))
    names(Feats.Spearman.EBS) <- Feats.Spearman.unique
    for(j in seq_len(length(Feats.Spearman.unique))){
        R <- 0
        for(k in seq_len(100)){
            if(!is.na(Rank.Spearman.mat[j,k])){
                # print(k)
                # print(Rank.mat[j,k])
                R <- R + sqrt(Rank.Spearman.mat[j,k])
                # print(R)
            }
        }
        Feats.Spearman.EBS[j] <- R/(Feats.Spearman.occ[j]^2)
    }
    ls.HC.Spearman.EBS[[i]] <- sort(Feats.Spearman.EBS)
}

save(ls.HC.Spearman.EBS,
     file = "./RData/ls.HC.Spearman.EBS.NSCLC.IBM.224.88.clinic.224.88.RData")

