library(reticulate)
library(survivalmodels)
library(mlr3)
library(mlr3proba)
library(paradox) # Define and Work with Parameter Spaces for Complex Algorithms
library(mlr3tuning)
library(mlr3extralearners)## learners are stored in mlr3extralearners
library("mlr3tuning")

# load data 
# IBM.224.mat, Clinic.224.df, IBM.88.mat, Clinic.88.df
load(file = "./RData/NSCLC.IBM.224.88.clinic.224.88.RData")


# normalization
IBM.224.mat.sd <- scale(IBM.224.mat, center = TRUE, scale = TRUE)
IBM.88.mat.sd <- scale(IBM.88.mat, center = TRUE, scale = TRUE)

# Load predefined random train-test splits 
load(file = "./RData/rslist.NSCLC.IBM.224.88.clinic.224.88.RData")


# load coxtime model
load(file = "./RData/lrn.coxtime.PCA.NSCLC.IBM.224.88.clinic.224.88.RData")
lrn.coxtime$param_set$values
lrn.cur = lrn.coxtime
# lrn.cur$param_set$set_values(num_nodes = c(128,128,128,128))

# repeat 100 times
N <- 100

res.mat <- matrix(NA, nrow = N, ncol = 24)
colnames(res.mat) <- c("cindex.train", "AUC.1y.train", "AUC.3y.train",
                       "AUC.5y.train", "IAUC.train", "bs.train", "logrank.train", "HR.train",
                       "cindex.test",  "AUC.1y.test", "AUC.3y.test",  
                       "AUC.5y.test",  "IAUC.test", "bs.test", "logrank.test", "HR.test",
                       "cindex.valid", "AUC.1y.valid", "AUC.3y.valid", 
                       "AUC.5y.valid", "IAUC.valid", "bs.valid", "logrank.valid", "HR.valid")
numOfFailed <- 0

for(i in seq_len(N)){
    print(paste0("N: ",i, " ------------"))
    
    idx.train <- rslist[[i]]$idx.train
    idx.test <- rslist[[i]]$idx.test
    
    Rad.train <- IBM.224.mat.sd[idx.train, ]
    Rad.test <- IBM.224.mat.sd[idx.test, ]
    Rad.valid <- IBM.88.mat.sd
    
    clinic.train <- Clinic.224.df[idx.train,]
    clinic.test <- Clinic.224.df[idx.test,]
    clinic.valid <- Clinic.88.df
    
    pr <- prcomp(Rad.train,
                 retx = TRUE, 
                 center = FALSE, 
                 scale = FALSE)   
    
    # Variance explained by principal components
    pr.var <- pr$sdev^2
    pve <- pr.var/sum(pr.var)
    
    # Cumulative variance explained
    cumpve <- cumsum(pve)
    nSel <- which(cumpve > 0.95)[1]  # Select the number of principal components
    
    RadC.train <- data.frame(pr$x[,1:nSel],
                             time = clinic.train$`surv.clinical.Time.Months`,
                             status = clinic.train$`surv.clinical.Event`)
    RadC.test <- data.frame(Rad.test%*%pr$rotation[,1:nSel],
                            time = clinic.test$`surv.clinical.Time.Months`,
                            status = clinic.test$`surv.clinical.Event`)
    RadC.valid <- data.frame(Rad.valid%*%pr$rotation[,1:nSel],
                             time = clinic.valid$`surv.clinical.Time.Months`,
                             status = clinic.valid$`surv.clinical.Event`)
    
    
    ## create our own task
    task.NSCLC <- TaskSurv$new(id = "NSCLC", # task id
                               backend = RadC.train,  # data, data.table or data.frame
                               time = "time",  # Name of the column for event time
                               event = "status") # Name of the column giving the event indicator
    # "0"/FALSE means alive (no event), "1"/TRUE means dead (event)
    
    task.test <- TaskSurv$new(id = "NSCLC.test", # task id
                              backend = RadC.test,  # data, data.table or data.frame
                              time = "time",  # Name of the column for event time
                              event = "status") # Name of the column giving the event indicator
    # "0"/FALSE means alive (no event), "1"/TRUE means dead (event)
    
    ## create our own task
    task.valid <- TaskSurv$new(id = "NSCLC.valid", # task id
                               backend = RadC.valid,  # data, data.table or data.frame
                               time = "time",  # Name of the column for event time
                               event = "status") # Name of the column giving the event indicator
    # "0"/FALSE means alive (no event), "1"/TRUE means dead (event)
    
    # train on the training set
    lrn.cur$train(task.NSCLC)
    
    # training set
    # RadScore-training set
    pred.train = lrn.cur$predict(task.NSCLC)
    lp.RS.train <- pred.train$crank
    
    if(length(unique(lp.RS.train)) > 1){
        # 5-year AUC
        perf.RS.train.5y <- tdrocc(x = lp.RS.train,
                                   surv.time = clinic.train$surv.clinical.Time.Months,
                                   surv.event = clinic.train$surv.clinical.Event,
                                   time = 5*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.train"] <- perf.RS.train.5y$AUC
        
        # 3-year AUC
        perf.RS.train.3y <- tdrocc(x = lp.RS.train,
                                   surv.time = clinic.train$surv.clinical.Time.Months,
                                   surv.event = clinic.train$surv.clinical.Event,
                                   time = 3*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.train"] <- perf.RS.train.3y$AUC
        
        # 5-year AUC
        perf.RS.train.1y <- tdrocc(x = lp.RS.train,
                                   surv.time = clinic.train$surv.clinical.Time.Months,
                                   surv.event = clinic.train$surv.clinical.Event,
                                   time = 1*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.train"] <- perf.RS.train.1y$AUC
        
        res.mat[i,"cindex.train"] <- concordance.index(lp.RS.train, 
                                                       clinic.train$surv.clinical.Time.Months,
                                                       clinic.train$surv.clinical.Event)$c.index
        # IAUC.train
        tt.train <- unique(sort(clinic.train$surv.clinical.Time.Months[clinic.train$surv.clinical.Event == 1]))
        mytdroc.train <- NULL
        for(i.tt in 1:length(tt.train)) {
            rr.train <- tdrocc(x=lp.RS.train, 
                               surv.time=clinic.train$surv.clinical.Time.Months, 
                               surv.event=clinic.train$surv.clinical.Event, 
                               time=tt.train[i.tt],
                               na.rm=TRUE, verbose=FALSE)
            mytdroc.train <- c(mytdroc.train, list(rr.train))
        }
        auc.train <- unlist(lapply(mytdroc.train, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.train"] <- iauc.comp(auc1=auc.train, auc2=auc.train, time=tt.train)$iauc1
        
        # Brier score.train
        bs.train <- data.frame(time = clinic.train$surv.clinical.Time.Months,
                               event = clinic.train$surv.clinical.Event,
                               score = lp.RS.train)
        res.mat[i,"bs.train"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.train, 
                               method="cox")$bsc.integrated
        
        # Log-rank.train x2
        RS.2cl.train <- rep(0, length = length(lp.RS.train))
        RS.2cl.train[which(lp.RS.train > median(lp.RS.train))] <- 1
        df.train <- data.frame(bs.train, RS.2cl = RS.2cl.train)
        sdf <- survdiff(Surv(time,event)~RS.2cl, data=df.train)
        res.mat[i,"logrank.train"] <- sdf$chisq
        
        # HR.train
        lp.RS.train.sd <- (lp.RS.train - min(lp.RS.train))/(max(lp.RS.train) - min(lp.RS.train))
        df.train <- data.frame(df.train, score.sd = lp.RS.train.sd)
        hr.train <- try(coxph(Surv(time, event) ~ score.sd, data = df.train),
                        silent = TRUE)
        if(!('try-error' %in% class(hr.train))){
            res.mat[i,"HR.train"] <- summary(hr.train)$coefficients[2]
        }else{
            print(paste0("Training set: Error in HR.valid!"))
        }
    }else{
        print("Training set: all predictions are 0s!")
        print(lp.RS.train)
    }
    
    
    
    # test set
    pred.test = lrn.cur$predict(task.test)
    lp.RS.test <- pred.test$crank
    
    if(length(unique(lp.RS.test)) > 1){
        # 5-year AUC
        perf.RS.test.5y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 5*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.test"] <- perf.RS.test.5y$AUC
        
        # 3-year AUC
        perf.RS.test.3y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 3*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.test"] <- perf.RS.test.3y$AUC
        
        # 1-year AUC
        perf.RS.test.1y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 1*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.test"] <- perf.RS.test.1y$AUC
        
        res.mat[i,"cindex.test"] <- concordance.index(lp.RS.test, 
                                                      clinic.test$surv.clinical.Time.Months,
                                                      clinic.test$surv.clinical.Event)$c.index
        
        # IAUC.test
        tt.test <- unique(sort(clinic.test$surv.clinical.Time.Months[clinic.test$surv.clinical.Event == 1]))
        mytdroc.test <- NULL
        for(i.tt in 1:length(tt.test)) {
            rr.test <- tdrocc(x=lp.RS.test, 
                              surv.time=clinic.test$surv.clinical.Time.Months, 
                              surv.event=clinic.test$surv.clinical.Event, 
                              time=tt.test[i.tt],
                              na.rm=TRUE, verbose=FALSE)
            mytdroc.test <- c(mytdroc.test, list(rr.test))
        }
        auc.test <- unlist(lapply(mytdroc.test, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.test"] <- iauc.comp(auc1=auc.test, auc2=auc.test, time=tt.test)$iauc1
        
        # Brier score
        bs.test <- data.frame(time = clinic.test$surv.clinical.Time.Months,
                              event = clinic.test$surv.clinical.Event,
                              score = lp.RS.test)
        res.mat[i,"bs.test"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.test, 
                               method="cox")$bsc.integrated
        
        # Log-rank.test x2
        RS.2cl.test <- rep(0, length = length(lp.RS.test))
        RS.2cl.test[which(lp.RS.test > median(lp.RS.train))] <- 1
        df.test <- data.frame(bs.test, RS.2cl = RS.2cl.test)
        sdf <- try(survdiff(Surv(time,event)~RS.2cl, data=df.test),
                   silent = TRUE)
        if(!('try-error' %in% class(sdf))){
            res.mat[i,"logrank.test"] <- sdf$chisq
        }else{
            print(paste0("Test set: Error in survdiff.fit, only 1 group!"))
        }
        
        
        # HR.test
        lp.RS.test.sd <- (lp.RS.test - min(lp.RS.test))/(max(lp.RS.test) - min(lp.RS.test))
        df.test <- data.frame(df.test, score.sd = lp.RS.test.sd)
        hr.test <- try(coxph(Surv(time, event) ~ score.sd, data = df.test),
                       silent = TRUE)
        if(!('try-error' %in% class(hr.test))){
            res.mat[i,"HR.test"] <- summary(hr.test)$coefficients[2]
        }else{
            print(paste0("Test set: Error in HR.test!"))
        }
    }else{
        print("Test set: all preditions are 0s!")
        print(lp.RS.test)
    } 
    
    
    # valid set
    pred.valid = lrn.cur$predict(task.valid)
    lp.RS.valid <- pred.valid$crank
    
    if(length(unique(lp.RS.valid)) > 1){
        # 5-year AUC
        perf.RS.valid.5y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 5*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.valid"] <- perf.RS.valid.5y$AUC
        
        # 3-year AUC
        perf.RS.valid.3y <- tdrocc(x = lp.RS.valid,
