# 10.1：Lasso-Cox -----------
# load data 

# IBM.224.mat, Clinic.224.df, IBM.88.mat, Clinic.88.df
load(file = "./RData/NSCLC.IBM.224.88.clinic.224.88.RData")


# normalization
IBM.224.mat.sd <- scale(IBM.224.mat, center = TRUE, scale = TRUE)
IBM.88.mat.sd <- scale(IBM.88.mat, center = TRUE, scale = TRUE)

# Load predefined random train-test splits 
load(file = "./RData/rslist.NSCLC.IBM.224.88.clinic.224.88.RData")

# Select survival-associated features
proteinCoxZP <- matrix(0, nrow=ncol(IBM.224.mat.sd), ncol=5)
rownames(proteinCoxZP) <- colnames(IBM.224.mat.sd)
colnames(proteinCoxZP) <- c("cox.z","cox.P","HR", "lower", "upper")

for(i in 1 : nrow(proteinCoxZP)){
    data.i <- data.frame(proteinExp = IBM.224.mat.sd[,i],
                         status = Clinic.224.df$surv.clinical.Event,
                         time = Clinic.224.df$surv.clinical.Time.Months)
    
    # CoxPH
    res.coxph <- coxph(Surv(time, status)~proteinExp, data = data.i)
    proteinCoxZP[i,c("HR","cox.z","cox.P")] <- summary(res.coxph)$coefficients[c(2,4,5)]
    proteinCoxZP[i,c("lower", "upper")] <- exp(confint(res.coxph))
}

# survival-associated features
Feats <- rownames(proteinCoxZP)[which(proteinCoxZP[,"cox.P"] < 0.1)]
save(Feats, file = "./RData/Feats.CoxP.0.1.NSCLC.IBM.224.88.clinic.224.88.RData")

