                                  time = 1*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.test"] <- perf.RS.test.1y$AUC
        
        res.mat[i,"cindex.test"] <- concordance.index(lp.RS.test, 
                                                      clinic.test$surv.clinical.Time.Months,
                                                      clinic.test$surv.clinical.Event)$c.index
        # IAUC.test
        tt.test <- unique(sort(clinic.test$surv.clinical.Time.Months[clinic.test$surv.clinical.Event == 1]))
        mytdroc.test <- NULL
        for(i.tt in 1:length(tt.test)) {
            rr.test <- tdrocc(x=lp.RS.test, 
                              surv.time=clinic.test$surv.clinical.Time.Months, 
                              surv.event=clinic.test$surv.clinical.Event, 
                              time=tt.test[i.tt],
                              na.rm=TRUE, verbose=FALSE)
            mytdroc.test <- c(mytdroc.test, list(rr.test))
        }
        auc.test <- unlist(lapply(mytdroc.test, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.test"] <- iauc.comp(auc1=auc.test, auc2=auc.test, time=tt.test)$iauc1
        
        # Brier score
        bs.test <- data.frame(time = clinic.test$surv.clinical.Time.Months,
                              event = clinic.test$surv.clinical.Event,
                              score = lp.RS.test)
        res.mat[i,"bs.test"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.test, 
                               method="cox")$bsc.integrated
        
        # Log-rank.test x2
        RS.2cl.test <- rep(0, length = length(lp.RS.test))
        RS.2cl.test[which(lp.RS.test >= median(lp.RS.train))] <- 1
        df.test <- data.frame(bs.test, RS.2cl = RS.2cl.test)
        sdf <- try(survdiff(Surv(time,event)~RS.2cl, data=df.test),
                   silent = TRUE)
        if(!('try-error' %in% class(sdf))){
            res.mat[i,"logrank.test"] <- sdf$chisq
        }else{
            print(paste0("Test set: Error in survdiff.fit, only 1 group!"))
        }
        
        
        # HR.test
        lp.RS.test.sd <- (lp.RS.test - min(lp.RS.test))/(max(lp.RS.test) - min(lp.RS.test))
        df.test <- data.frame(df.test, score.sd = lp.RS.test.sd)
        res.mat[i,"HR.test"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                              data = df.test))$coefficients[2]
        
        
        # valid set
        lp.RS.valid <- predict(object = mod.i, newdata = PCData.valid, 
                               type = "lp")
        lp.RS.valid <- as.vector(lp.RS.valid)
        
        
        # 5-year AUC
        perf.RS.valid.5y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 5*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.valid"] <- perf.RS.valid.5y$AUC
        
        # 3-year AUC
        perf.RS.valid.3y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 3*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.valid"] <- perf.RS.valid.3y$AUC
        
        # 1-year AUC
        perf.RS.valid.1y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 1*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.valid"] <- perf.RS.valid.1y$AUC
        
        res.mat[i,"cindex.valid"] <- concordance.index(lp.RS.valid, 
                                                       clinic.valid$surv.clinical.Time.Months,
                                                       clinic.valid$surv.clinical.Event)$c.index
        # IAUC.valid
        tt.valid <- unique(sort(clinic.valid$surv.clinical.Time.Months[clinic.valid$surv.clinical.Event == 1]))
        mytdroc.valid <- NULL
        for(i.tt in 1:length(tt.valid)) {
            rr.valid <- tdrocc(x=lp.RS.valid, 
                               surv.time=clinic.valid$surv.clinical.Time.Months, 
                               surv.event=clinic.valid$surv.clinical.Event, 
                               time=tt.valid[i.tt],
                               na.rm=TRUE, verbose=FALSE)
            mytdroc.valid <- c(mytdroc.valid, list(rr.valid))
        }
        auc.valid <- unlist(lapply(mytdroc.valid, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.valid"] <- iauc.comp(auc1=auc.valid, auc2=auc.valid, time=tt.valid)$iauc1
        
        # Brier score
        bs.valid <- data.frame(time = clinic.valid$surv.clinical.Time.Months,
                               event = clinic.valid$surv.clinical.Event,
                               score = lp.RS.valid)
        res.mat[i,"bs.valid"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.valid, 
                               method="cox")$bsc.integrated
        
        # Log-rank.valid x2
        RS.2cl.valid <- rep(0, length = length(lp.RS.valid))
        RS.2cl.valid[which(lp.RS.valid >= median(lp.RS.train))] <- 1
        df.valid <- data.frame(bs.valid, RS.2cl = RS.2cl.valid)
        sdf <- try(survdiff(Surv(time,event)~RS.2cl, data=df.valid),
                   silent = TRUE)
        if(!('try-error' %in% class(sdf))){
            res.mat[i,"logrank.valid"] <- sdf$chisq
        }else{
            print(paste0("Valid set: Error in survdiff.fit, only 1 group!"))
        }
        
        # HR.valid
        lp.RS.valid.sd <- (lp.RS.valid - min(lp.RS.valid))/(max(lp.RS.valid) - min(lp.RS.valid))
        df.valid <- data.frame(df.valid, score.sd = lp.RS.valid.sd)
        res.mat[i,"HR.valid"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                               data = df.valid))$coefficients[2]
    }
}

