save(results, file = "./RData/consensus.Results.RData")

# load CC results
load(file = "./RData/consensus.Results.RData")
Feats.c1 <- names(which(results[[3]]$consensusClass==1))
Feats.c2 <- names(which(results[[3]]$consensusClass==2))
Feats.c3 <- names(which(results[[3]]$consensusClass==3))

# repeat 100 times
N <- 100
