meanRes <- rep(0, length = 24)
medianRes <- rep(0, length = 24)
sdRes <- rep(0, length = 24)
RSDRes <- rep(0, length = 24)
for(i in seq_len(ncol(res.mat))){
    meanRes[i] <- mean(res.mat[,i], na.rm = TRUE)
    medianRes[i] <- median(res.mat[,i], na.rm = TRUE)
    sdRes[i] <- sd(res.mat[,i], na.rm = TRUE)
    RSDRes[i] <- 100*sdRes[i]/meanRes[i]
}
res.mean <- data.frame(mean = meanRes,
                       median = medianRes,
                       sd = sdRes,
                       RSD = RSDRes)
rownames(res.mean) <- colnames(res.mat)

res.CCPCA.Lasso <- list(res = res.mat,
                      res.mean = res.mean,
                      numOfFailed = numOfFailed)


# 11.2：Ridge-Cox -----------
# load data 

# IBM.224.mat, Clinic.224.df, IBM.88.mat, Clinic.88.df
load(file = "./RData/NSCLC.IBM.224.88.clinic.224.88.RData")


# normalization
IBM.224.mat.sd <- scale(IBM.224.mat, center = TRUE, scale = TRUE)
IBM.88.mat.sd <- scale(IBM.88.mat, center = TRUE, scale = TRUE)

# Load predefined random train-test splits 
load(file = "./RData/rslist.NSCLC.IBM.224.88.clinic.224.88.RData")

# load CC results
load(file = "./RData/consensus.Results.RData")
Feats.c1 <- names(which(results[[3]]$consensusClass==1))
Feats.c2 <- names(which(results[[3]]$consensusClass==2))
Feats.c3 <- names(which(results[[3]]$consensusClass==3))

# repeat 100 times
N <- 100
# mod.LassoCox <- vector(mode = "list", length = N)
res.mat <- matrix(NA, nrow = N, ncol = 24)
colnames(res.mat) <- c("cindex.train", "AUC.1y.train", "AUC.3y.train",
                       "AUC.5y.train", "IAUC.train", "bs.train", "logrank.train", "HR.train",
                       "cindex.test",  "AUC.1y.test", "AUC.3y.test",  
                       "AUC.5y.test",  "IAUC.test", "bs.test", "logrank.test", "HR.test",
                       "cindex.valid", "AUC.1y.valid", "AUC.3y.valid", 
                       "AUC.5y.valid", "IAUC.valid", "bs.valid", "logrank.valid", "HR.valid")
numOfFailed <- 0  # Lasso-Cox Number of failed model training attempts

for(i in seq_len(N)){
    print(i)
    
    idx.train <- rslist[[i]]$idx.train
    idx.test <- rslist[[i]]$idx.test
    
    clinic.train <- Clinic.224.df[idx.train,]
    clinic.test <- Clinic.224.df[idx.test,]
    clinic.valid <- Clinic.88.df
    
    # c1uster 1
    Rad.train.c1 <- IBM.224.mat.sd[idx.train, Feats.c1]
    Rad.test.c1 <- IBM.224.mat.sd[idx.test,Feats.c1]
    Rad.valid.c1 <- IBM.88.mat.sd[,Feats.c1]
    
    pr.c1 <- prcomp(Rad.train.c1,
                    retx = TRUE, 
                    center = FALSE, 
                    scale = FALSE)   
    
    # Variance explained by principal components
    pr.var <- pr.c1$sdev^2
    pve <- pr.var/sum(pr.var)
    
    # Cumulative variance explained
    cumpve <- cumsum(pve)
    nSel.c1 <- which(cumpve > 0.95)[1]  # Select the number of principal components
    
    # c1uster 2
    Rad.train.c2 <- IBM.224.mat.sd[idx.train, Feats.c2]
    Rad.test.c2 <- IBM.224.mat.sd[idx.test,Feats.c2]
    Rad.valid.c2 <- IBM.88.mat.sd[,Feats.c2]
    
    pr.c2 <- prcomp(Rad.train.c2,
                    retx = TRUE, 
                    center = FALSE, 
                    scale = FALSE)   
    
    # Variance explained by principal components
    pr.var <- pr.c2$sdev^2
    pve <- pr.var/sum(pr.var)
    
    # Cumulative variance explained
    cumpve <- cumsum(pve)
    nSel.c2 <- which(cumpve > 0.95)[1]  # Select the number of principal components
    
    # c1uster 3
    Rad.train.c3 <- IBM.224.mat.sd[idx.train, Feats.c3]
    Rad.test.c3 <- IBM.224.mat.sd[idx.test,Feats.c3]
    Rad.valid.c3 <- IBM.88.mat.sd[,Feats.c3]
    
    pr.c3 <- prcomp(Rad.train.c3,
                    retx = TRUE, 
                    center = FALSE, 
                    scale = FALSE)   
    
    # Variance explained by principal components
    pr.var <- pr.c3$sdev^2
    pve <- pr.var/sum(pr.var)
    
    # Cumulative variance explained
    cumpve <- cumsum(pve)
    nSel.c3 <- which(cumpve > 0.95)[1]  # Select the number of principal components
    
    # train
    PCData.train.c1 <- pr.c1$x[,1:nSel.c1]
    colnames(PCData.train.c1) <- paste0("c1", colnames(PCData.train.c1))
    
    PCData.train.c2 <- pr.c2$x[,1:nSel.c2]
    colnames(PCData.train.c2) <- paste0("c2", colnames(PCData.train.c2))
    
    PCData.train.c3 <- pr.c3$x[,1:nSel.c3]
    colnames(PCData.train.c3) <- paste0("c3", colnames(PCData.train.c3))
    
    # test
    PCData.test.c1 <- Rad.test.c1%*%pr.c1$rotation[,1:nSel.c1]
    colnames(PCData.test.c1) <- paste0("c1", colnames(PCData.test.c1))
    
    PCData.test.c2 <- Rad.test.c2%*%pr.c2$rotation[,1:nSel.c2]
    colnames(PCData.test.c2) <- paste0("c2", colnames(PCData.test.c2))
    
    PCData.test.c3 <- Rad.test.c3%*%pr.c3$rotation[,1:nSel.c3]
    colnames(PCData.test.c3) <- paste0("c3", colnames(PCData.test.c3))
    
    # valid
    PCData.valid.c1 <- Rad.valid.c1%*%pr.c1$rotation[,1:nSel.c1]
    colnames(PCData.valid.c1) <- paste0("c1", colnames(PCData.valid.c1))
    
    PCData.valid.c2 <- Rad.valid.c2%*%pr.c2$rotation[,1:nSel.c2]
    colnames(PCData.valid.c2) <- paste0("c2", colnames(PCData.valid.c2))
    
    PCData.valid.c3 <- Rad.valid.c3%*%pr.c3$rotation[,1:nSel.c3]
    colnames(PCData.valid.c3) <- paste0("c3", colnames(PCData.valid.c3))
    
    PCData.train <- as.matrix(data.frame(PCData.train.c1,
                                         PCData.train.c2,
                                         PCData.train.c3))
    PCData.test <- as.matrix(data.frame(PCData.test.c1,
                                        PCData.test.c2,
                                        PCData.test.c3))
    PCData.valid <- as.matrix(data.frame(PCData.valid.c1,
                                         PCData.valid.c2,
                                         PCData.valid.c3))
    
    
    mod.i <- cv.glmnet(x = PCData.train,
                       y = Surv(time = clinic.train$surv.clinical.Time.Months,
                                event = clinic.train$surv.clinical.Event),
                       family = "cox",
                       nfolds = 5,
                       # dfmax = 5,  # the maximum number of variables in the model
                       # pmax = 5,
                       alpha = 0  # lasso
                       # penalty.factor = TPWeight
    )
    
    # mod.LassoCox[[i]] <- mod.i
    
    cf <- coef(mod.i,s=c("lambda.min"))
    numOfFeats <- length(which(cf != 0))
    if(numOfFeats == 0){
        print(paste0("i = ", i, ", Lambda.min failed!"))
        numOfFailed <- numOfFailed + 1
        # idx.nzero <- which(mod.i$nzero != 0)
        # idx.cvmin <- which.min(mod.i$cvm[idx.nzero])
        # opt.lambda <- mod.i$lambda[idx.nzero[idx.cvmin]] 
    }else{
        opt.lambda <- mod.i$lambda.min
        
        # RadScore-training set
        lp.RS.train <- predict(mod.i, newx = PCData.train, s=opt.lambda)
        lp.RS.train <- as.vector(lp.RS.train)
        
        # 5-year AUC
        perf.RS.train.5y <- tdrocc(x = lp.RS.train,
                                   surv.time = clinic.train$surv.clinical.Time.Months,
                                   surv.event = clinic.train$surv.clinical.Event,
                                   time = 5*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.train"] <- perf.RS.train.5y$AUC
        
        # 3-year AUC
        perf.RS.train.3y <- tdrocc(x = lp.RS.train,
                                   surv.time = clinic.train$surv.clinical.Time.Months,
                                   surv.event = clinic.train$surv.clinical.Event,
                                   time = 3*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.train"] <- perf.RS.train.3y$AUC
        
        # 5-year AUC
        perf.RS.train.1y <- tdrocc(x = lp.RS.train,
                                   surv.time = clinic.train$surv.clinical.Time.Months,
                                   surv.event = clinic.train$surv.clinical.Event,
                                   time = 1*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.train"] <- perf.RS.train.1y$AUC
        
        res.mat[i,"cindex.train"] <- concordance.index(lp.RS.train, 
                                                       clinic.train$surv.clinical.Time.Months,
                                                       clinic.train$surv.clinical.Event)$c.index
        # IAUC.train
        tt.train <- unique(sort(clinic.train$surv.clinical.Time.Months[clinic.train$surv.clinical.Event == 1]))
        mytdroc.train <- NULL
        for(i.tt in 1:length(tt.train)) {
            rr.train <- tdrocc(x=lp.RS.train, 
                               surv.time=clinic.train$surv.clinical.Time.Months, 
                               surv.event=clinic.train$surv.clinical.Event, 
                               time=tt.train[i.tt],
                               na.rm=TRUE, verbose=FALSE)
            mytdroc.train <- c(mytdroc.train, list(rr.train))
        }
        auc.train <- unlist(lapply(mytdroc.train, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.train"] <- iauc.comp(auc1=auc.train, auc2=auc.train, time=tt.train)$iauc1
        
        # Brier score.train
        bs.train <- data.frame(time = clinic.train$surv.clinical.Time.Months,
                               event = clinic.train$surv.clinical.Event,
                               score = lp.RS.train)
        res.mat[i,"bs.train"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.train, 
                               method="cox")$bsc.integrated
        
        # Log-rank.train x2
        RS.2cl.train <- rep(0, length = length(lp.RS.train))
        RS.2cl.train[which(lp.RS.train >= median(lp.RS.train))] <- 1
        df.train <- data.frame(bs.train, RS.2cl = RS.2cl.train)
        sdf <- survdiff(Surv(time,event)~RS.2cl, data=df.train)
        res.mat[i,"logrank.train"] <- sdf$chisq
        
        # HR.train
        lp.RS.train.sd <- (lp.RS.train - min(lp.RS.train))/(max(lp.RS.train) - min(lp.RS.train))
        df.train <- data.frame(df.train, score.sd = lp.RS.train.sd)
        res.mat[i,"HR.train"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                               data = df.train))$coefficients[2]
        
        # RadScore-test set
        lp.RS.test <- predict(mod.i, newx = PCData.test, s=opt.lambda)
        lp.RS.test <- as.vector(lp.RS.test)
        
        # 5-year AUC
        perf.RS.test.5y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 5*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.test"] <- perf.RS.test.5y$AUC
        
        # 3-year AUC
        perf.RS.test.3y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 3*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.test"] <- perf.RS.test.3y$AUC
        
        # 1-year AUC
        perf.RS.test.1y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 1*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.test"] <- perf.RS.test.1y$AUC
        
        res.mat[i,"cindex.test"] <- concordance.index(lp.RS.test, 
                                                      clinic.test$surv.clinical.Time.Months,
                                                      clinic.test$surv.clinical.Event)$c.index
        # IAUC.test
        tt.test <- unique(sort(clinic.test$surv.clinical.Time.Months[clinic.test$surv.clinical.Event == 1]))
        mytdroc.test <- NULL
        for(i.tt in 1:length(tt.test)) {
            rr.test <- tdrocc(x=lp.RS.test, 
                              surv.time=clinic.test$surv.clinical.Time.Months, 
                              surv.event=clinic.test$surv.clinical.Event, 
                              time=tt.test[i.tt],
                              na.rm=TRUE, verbose=FALSE)
            mytdroc.test <- c(mytdroc.test, list(rr.test))
        }
        auc.test <- unlist(lapply(mytdroc.test, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.test"] <- iauc.comp(auc1=auc.test, auc2=auc.test, time=tt.test)$iauc1
        
        # Brier score
        bs.test <- data.frame(time = clinic.test$surv.clinical.Time.Months,
                              event = clinic.test$surv.clinical.Event,
                              score = lp.RS.test)
        res.mat[i,"bs.test"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.test, 
                               method="cox")$bsc.integrated
        
        # Log-rank.test x2
        RS.2cl.test <- rep(0, length = length(lp.RS.test))
        RS.2cl.test[which(lp.RS.test >= median(lp.RS.train))] <- 1
        df.test <- data.frame(bs.test, RS.2cl = RS.2cl.test)
        sdf <- try(survdiff(Surv(time,event)~RS.2cl, data=df.test),
                   silent = TRUE)
        if(!('try-error' %in% class(sdf))){
            res.mat[i,"logrank.test"] <- sdf$chisq
        }else{
            print(paste0("Test set: Error in survdiff.fit, only 1 group!"))
        }
        
        
        # HR.test
        lp.RS.test.sd <- (lp.RS.test - min(lp.RS.test))/(max(lp.RS.test) - min(lp.RS.test))
        df.test <- data.frame(df.test, score.sd = lp.RS.test.sd)
        res.mat[i,"HR.test"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                              data = df.test))$coefficients[2]
        
        
        # RadScore-valid set
        lp.RS.valid <- predict(mod.i, newx = PCData.valid, s=opt.lambda)
        lp.RS.valid <- as.vector(lp.RS.valid)
        
        # 5-year AUC
        perf.RS.valid.5y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 5*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.valid"] <- perf.RS.valid.5y$AUC
        
        # 3-year AUC
        perf.RS.valid.3y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 3*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.valid"] <- perf.RS.valid.3y$AUC
        
        # 1-year AUC
        perf.RS.valid.1y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 1*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.valid"] <- perf.RS.valid.1y$AUC
        
        res.mat[i,"cindex.valid"] <- concordance.index(lp.RS.valid, 
                                                       clinic.valid$surv.clinical.Time.Months,
                                                       clinic.valid$surv.clinical.Event)$c.index
        
        # IAUC.valid
        tt.valid <- unique(sort(clinic.valid$surv.clinical.Time.Months[clinic.valid$surv.clinical.Event == 1]))
        mytdroc.valid <- NULL
        for(i.tt in 1:length(tt.valid)) {
            rr.valid <- tdrocc(x=lp.RS.valid, 
                               surv.time=clinic.valid$surv.clinical.Time.Months, 
                               surv.event=clinic.valid$surv.clinical.Event, 
                               time=tt.valid[i.tt],
                               na.rm=TRUE, verbose=FALSE)
            mytdroc.valid <- c(mytdroc.valid, list(rr.valid))
        }
        auc.valid <- unlist(lapply(mytdroc.valid, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.valid"] <- iauc.comp(auc1=auc.valid, auc2=auc.valid, time=tt.valid)$iauc1
        
        # Brier score
        bs.valid <- data.frame(time = clinic.valid$surv.clinical.Time.Months,
                               event = clinic.valid$surv.clinical.Event,
                               score = lp.RS.valid)
        res.mat[i,"bs.valid"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.valid, 
                               method="cox")$bsc.integrated
        
        # Log-rank.valid x2
        RS.2cl.valid <- rep(0, length = length(lp.RS.valid))
        RS.2cl.valid[which(lp.RS.valid >= median(lp.RS.train))] <- 1
        df.valid <- data.frame(bs.valid, RS.2cl = RS.2cl.valid)
        sdf <- try(survdiff(Surv(time,event)~RS.2cl, data=df.valid),
                   silent = TRUE)
        if(!('try-error' %in% class(sdf))){
            res.mat[i,"logrank.valid"] <- sdf$chisq
        }else{
            print(paste0("Valid set: Error in survdiff.fit, only 1 group!"))
        }
        
        # HR.valid
        lp.RS.valid.sd <- (lp.RS.valid - min(lp.RS.valid))/(max(lp.RS.valid) - min(lp.RS.valid))
        df.valid <- data.frame(df.valid, score.sd = lp.RS.valid.sd)
        res.mat[i,"HR.valid"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                               data = df.valid))$coefficients[2]
    }
    
}

# Summarize average performance
meanRes <- rep(0, length = 24)
medianRes <- rep(0, length = 24)
sdRes <- rep(0, length = 24)
RSDRes <- rep(0, length = 24)
for(i in seq_len(ncol(res.mat))){
    meanRes[i] <- mean(res.mat[,i], na.rm = TRUE)
    medianRes[i] <- median(res.mat[,i], na.rm = TRUE)
    sdRes[i] <- sd(res.mat[,i], na.rm = TRUE)
    RSDRes[i] <- 100*sdRes[i]/meanRes[i]
}
res.mean <- data.frame(mean = meanRes,
                       median = medianRes,
                       sd = sdRes,
                       RSD = RSDRes)
rownames(res.mean) <- colnames(res.mat)

res.CCPCA.Ridge <- list(res = res.mat,
                      res.mean = res.mean,
                      numOfFailed = numOfFailed)



# 11.3：EN-Cox (alpha = 0.5) -----------
# load data 
# IBM.224.mat, Clinic.224.df, IBM.88.mat, Clinic.88.df
load(file = "./RData/NSCLC.IBM.224.88.clinic.224.88.RData")


# normalization
IBM.224.mat.sd <- scale(IBM.224.mat, center = TRUE, scale = TRUE)
IBM.88.mat.sd <- scale(IBM.88.mat, center = TRUE, scale = TRUE)

# Load predefined random train-test splits 
load(file = "./RData/rslist.NSCLC.IBM.224.88.clinic.224.88.RData")

# load CC results
load(file = "./RData/consensus.Results.RData")
Feats.c1 <- names(which(results[[3]]$consensusClass==1))
Feats.c2 <- names(which(results[[3]]$consensusClass==2))
Feats.c3 <- names(which(results[[3]]$consensusClass==3))

# repeat 100 times
N <- 100
# mod.LassoCox <- vector(mode = "list", length = N)
res.mat <- matrix(NA, nrow = N, ncol = 24)
colnames(res.mat) <- c("cindex.train", "AUC.1y.train", "AUC.3y.train",
                       "AUC.5y.train", "IAUC.train", "bs.train", "logrank.train", "HR.train",
                       "cindex.test",  "AUC.1y.test", "AUC.3y.test",  
                       "AUC.5y.test",  "IAUC.test", "bs.test", "logrank.test", "HR.test",
                       "cindex.valid", "AUC.1y.valid", "AUC.3y.valid", 
                       "AUC.5y.valid", "IAUC.valid", "bs.valid", "logrank.valid", "HR.valid")
numOfFailed <- 0  # Lasso-Cox Number of failed model training attempts

for(i in seq_len(N)){
    print(i)
    
    idx.train <- rslist[[i]]$idx.train
    idx.test <- rslist[[i]]$idx.test
    
    clinic.train <- Clinic.224.df[idx.train,]
    clinic.test <- Clinic.224.df[idx.test,]
    clinic.valid <- Clinic.88.df
    
    # c1uster 1
    Rad.train.c1 <- IBM.224.mat.sd[idx.train, Feats.c1]
    Rad.test.c1 <- IBM.224.mat.sd[idx.test,Feats.c1]
    Rad.valid.c1 <- IBM.88.mat.sd[,Feats.c1]
    
    pr.c1 <- prcomp(Rad.train.c1,
                    retx = TRUE, 
                    center = FALSE, 
                    scale = FALSE)   
    
    # Variance explained by principal components
    pr.var <- pr.c1$sdev^2
    pve <- pr.var/sum(pr.var)
    
    # Cumulative variance explained
    cumpve <- cumsum(pve)
    nSel.c1 <- which(cumpve > 0.95)[1]  # Select the number of principal components
    
    # c1uster 2
    Rad.train.c2 <- IBM.224.mat.sd[idx.train, Feats.c2]
    Rad.test.c2 <- IBM.224.mat.sd[idx.test,Feats.c2]
    Rad.valid.c2 <- IBM.88.mat.sd[,Feats.c2]
    
    pr.c2 <- prcomp(Rad.train.c2,
                    retx = TRUE, 
                    center = FALSE, 
                    scale = FALSE)   
    
    # Variance explained by principal components
    pr.var <- pr.c2$sdev^2
    pve <- pr.var/sum(pr.var)
    
    # Cumulative variance explained
    cumpve <- cumsum(pve)
    nSel.c2 <- which(cumpve > 0.95)[1]  # Select the number of principal components
    
    # c1uster 3
    Rad.train.c3 <- IBM.224.mat.sd[idx.train, Feats.c3]
    Rad.test.c3 <- IBM.224.mat.sd[idx.test,Feats.c3]
    Rad.valid.c3 <- IBM.88.mat.sd[,Feats.c3]
    
    pr.c3 <- prcomp(Rad.train.c3,
                    retx = TRUE, 
                    center = FALSE, 
                    scale = FALSE)   
    
    # Variance explained by principal components
    pr.var <- pr.c3$sdev^2
    pve <- pr.var/sum(pr.var)
    
    # Cumulative variance explained
    cumpve <- cumsum(pve)
    nSel.c3 <- which(cumpve > 0.95)[1]  # Select the number of principal components
    
    # train
    PCData.train.c1 <- pr.c1$x[,1:nSel.c1]
    colnames(PCData.train.c1) <- paste0("c1", colnames(PCData.train.c1))
    
    PCData.train.c2 <- pr.c2$x[,1:nSel.c2]
    colnames(PCData.train.c2) <- paste0("c2", colnames(PCData.train.c2))
    
    PCData.train.c3 <- pr.c3$x[,1:nSel.c3]
    colnames(PCData.train.c3) <- paste0("c3", colnames(PCData.train.c3))
    
    # test
    PCData.test.c1 <- Rad.test.c1%*%pr.c1$rotation[,1:nSel.c1]
    colnames(PCData.test.c1) <- paste0("c1", colnames(PCData.test.c1))
    
    PCData.test.c2 <- Rad.test.c2%*%pr.c2$rotation[,1:nSel.c2]
    colnames(PCData.test.c2) <- paste0("c2", colnames(PCData.test.c2))
    
    PCData.test.c3 <- Rad.test.c3%*%pr.c3$rotation[,1:nSel.c3]
    colnames(PCData.test.c3) <- paste0("c3", colnames(PCData.test.c3))
    
    # valid
    PCData.valid.c1 <- Rad.valid.c1%*%pr.c1$rotation[,1:nSel.c1]
    colnames(PCData.valid.c1) <- paste0("c1", colnames(PCData.valid.c1))
    
    PCData.valid.c2 <- Rad.valid.c2%*%pr.c2$rotation[,1:nSel.c2]
    colnames(PCData.valid.c2) <- paste0("c2", colnames(PCData.valid.c2))
    
    PCData.valid.c3 <- Rad.valid.c3%*%pr.c3$rotation[,1:nSel.c3]
    colnames(PCData.valid.c3) <- paste0("c3", colnames(PCData.valid.c3))
    
    PCData.train <- as.matrix(data.frame(PCData.train.c1,
                                         PCData.train.c2,
                                         PCData.train.c3))
    PCData.test <- as.matrix(data.frame(PCData.test.c1,
                                        PCData.test.c2,
                                        PCData.test.c3))
    PCData.valid <- as.matrix(data.frame(PCData.valid.c1,
                                         PCData.valid.c2,
                                         PCData.valid.c3))
    
    mod.i <- cv.glmnet(x = PCData.train,
                       y = Surv(time = clinic.train$surv.clinical.Time.Months,
                                event = clinic.train$surv.clinical.Event),
                       family = "cox",
                       nfolds = 5,
                       # dfmax = 5,  # the maximum number of variables in the model
                       # pmax = 5,
                       alpha = 0.5  # lasso
                       # penalty.factor = TPWeight
    )
    
    # mod.LassoCox[[i]] <- mod.i
    
    cf <- coef(mod.i,s=c("lambda.min"))
    numOfFeats <- length(which(cf != 0))
    if(numOfFeats == 0){
        print(paste0("i = ", i, ", Lambda.min failed!"))
        numOfFailed <- numOfFailed + 1
        # idx.nzero <- which(mod.i$nzero != 0)
        # idx.cvmin <- which.min(mod.i$cvm[idx.nzero])
        # opt.lambda <- mod.i$lambda[idx.nzero[idx.cvmin]] 
    }else{
        opt.lambda <- mod.i$lambda.min
        
        # RadScore-training set
        lp.RS.train <- predict(mod.i, newx = PCData.train, s=opt.lambda)
        lp.RS.train <- as.vector(lp.RS.train)
        
        # 5-year AUC
        perf.RS.train.5y <- tdrocc(x = lp.RS.train,
                                   surv.time = clinic.train$surv.clinical.Time.Months,
                                   surv.event = clinic.train$surv.clinical.Event,
                                   time = 5*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.train"] <- perf.RS.train.5y$AUC
        
        # 3-year AUC
        perf.RS.train.3y <- tdrocc(x = lp.RS.train,
                                   surv.time = clinic.train$surv.clinical.Time.Months,
                                   surv.event = clinic.train$surv.clinical.Event,
                                   time = 3*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.train"] <- perf.RS.train.3y$AUC
        
        # 5-year AUC
        perf.RS.train.1y <- tdrocc(x = lp.RS.train,
                                   surv.time = clinic.train$surv.clinical.Time.Months,
                                   surv.event = clinic.train$surv.clinical.Event,
                                   time = 1*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.train"] <- perf.RS.train.1y$AUC
        
        res.mat[i,"cindex.train"] <- concordance.index(lp.RS.train, 
                                                       clinic.train$surv.clinical.Time.Months,
                                                       clinic.train$surv.clinical.Event)$c.index
        # IAUC.train
        tt.train <- unique(sort(clinic.train$surv.clinical.Time.Months[clinic.train$surv.clinical.Event == 1]))
        mytdroc.train <- NULL
        for(i.tt in 1:length(tt.train)) {
            rr.train <- tdrocc(x=lp.RS.train, 
                               surv.time=clinic.train$surv.clinical.Time.Months, 
                               surv.event=clinic.train$surv.clinical.Event, 
                               time=tt.train[i.tt],
                               na.rm=TRUE, verbose=FALSE)
            mytdroc.train <- c(mytdroc.train, list(rr.train))
        }
        auc.train <- unlist(lapply(mytdroc.train, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.train"] <- iauc.comp(auc1=auc.train, auc2=auc.train, time=tt.train)$iauc1
        
        # Brier score.train
        bs.train <- data.frame(time = clinic.train$surv.clinical.Time.Months,
                               event = clinic.train$surv.clinical.Event,
                               score = lp.RS.train)
        res.mat[i,"bs.train"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.train, 
                               method="cox")$bsc.integrated
        
        # Log-rank.train x2
        RS.2cl.train <- rep(0, length = length(lp.RS.train))
        RS.2cl.train[which(lp.RS.train >= median(lp.RS.train))] <- 1
        df.train <- data.frame(bs.train, RS.2cl = RS.2cl.train)
        sdf <- survdiff(Surv(time,event)~RS.2cl, data=df.train)
        res.mat[i,"logrank.train"] <- sdf$chisq
        
        # HR.train
        lp.RS.train.sd <- (lp.RS.train - min(lp.RS.train))/(max(lp.RS.train) - min(lp.RS.train))
        df.train <- data.frame(df.train, score.sd = lp.RS.train.sd)
        res.mat[i,"HR.train"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                               data = df.train))$coefficients[2]
        
        # RadScore-test set
        lp.RS.test <- predict(mod.i, newx = PCData.test, s=opt.lambda)
        lp.RS.test <- as.vector(lp.RS.test)
        
        # 5-year AUC
        perf.RS.test.5y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 5*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.test"] <- perf.RS.test.5y$AUC
        
        # 3-year AUC
        perf.RS.test.3y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 3*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.test"] <- perf.RS.test.3y$AUC
        
        # 1-year AUC
        perf.RS.test.1y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 1*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.test"] <- perf.RS.test.1y$AUC
        
        res.mat[i,"cindex.test"] <- concordance.index(lp.RS.test, 
                                                      clinic.test$surv.clinical.Time.Months,
                                                      clinic.test$surv.clinical.Event)$c.index
        # IAUC.test
        tt.test <- unique(sort(clinic.test$surv.clinical.Time.Months[clinic.test$surv.clinical.Event == 1]))
        mytdroc.test <- NULL
        for(i.tt in 1:length(tt.test)) {
            rr.test <- tdrocc(x=lp.RS.test, 
                              surv.time=clinic.test$surv.clinical.Time.Months, 
                              surv.event=clinic.test$surv.clinical.Event, 
                              time=tt.test[i.tt],
                              na.rm=TRUE, verbose=FALSE)
            mytdroc.test <- c(mytdroc.test, list(rr.test))
        }
        auc.test <- unlist(lapply(mytdroc.test, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.test"] <- iauc.comp(auc1=auc.test, auc2=auc.test, time=tt.test)$iauc1
        
        # Brier score
        bs.test <- data.frame(time = clinic.test$surv.clinical.Time.Months,
                              event = clinic.test$surv.clinical.Event,
                              score = lp.RS.test)
        res.mat[i,"bs.test"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.test, 
                               method="cox")$bsc.integrated
        
        # Log-rank.test x2
        RS.2cl.test <- rep(0, length = length(lp.RS.test))
        RS.2cl.test[which(lp.RS.test >= median(lp.RS.train))] <- 1
        df.test <- data.frame(bs.test, RS.2cl = RS.2cl.test)
        sdf <- try(survdiff(Surv(time,event)~RS.2cl, data=df.test),
                   silent = TRUE)
        if(!('try-error' %in% class(sdf))){
            res.mat[i,"logrank.test"] <- sdf$chisq
        }else{
            print(paste0("Test set: Error in survdiff.fit, only 1 group!"))
        }
        
        
        # HR.test
        lp.RS.test.sd <- (lp.RS.test - min(lp.RS.test))/(max(lp.RS.test) - min(lp.RS.test))
        df.test <- data.frame(df.test, score.sd = lp.RS.test.sd)
        res.mat[i,"HR.test"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                              data = df.test))$coefficients[2]
        
        
        # RadScore-valid set
        lp.RS.valid <- predict(mod.i, newx = PCData.valid, s=opt.lambda)
        lp.RS.valid <- as.vector(lp.RS.valid)
        
        # 5-year AUC
        perf.RS.valid.5y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 5*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.valid"] <- perf.RS.valid.5y$AUC
        
        # 3-year AUC
        perf.RS.valid.3y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 3*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.valid"] <- perf.RS.valid.3y$AUC
        
        # 1-year AUC
        perf.RS.valid.1y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 1*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.valid"] <- perf.RS.valid.1y$AUC
        
        res.mat[i,"cindex.valid"] <- concordance.index(lp.RS.valid, 
                                                       clinic.valid$surv.clinical.Time.Months,
                                                       clinic.valid$surv.clinical.Event)$c.index
        
        # IAUC.valid
        tt.valid <- unique(sort(clinic.valid$surv.clinical.Time.Months[clinic.valid$surv.clinical.Event == 1]))
        mytdroc.valid <- NULL
        for(i.tt in 1:length(tt.valid)) {
            rr.valid <- tdrocc(x=lp.RS.valid, 
                               surv.time=clinic.valid$surv.clinical.Time.Months, 
                               surv.event=clinic.valid$surv.clinical.Event, 
                               time=tt.valid[i.tt],
                               na.rm=TRUE, verbose=FALSE)
            mytdroc.valid <- c(mytdroc.valid, list(rr.valid))
        }
        auc.valid <- unlist(lapply(mytdroc.valid, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.valid"] <- iauc.comp(auc1=auc.valid, auc2=auc.valid, time=tt.valid)$iauc1
        
        # Brier score
        bs.valid <- data.frame(time = clinic.valid$surv.clinical.Time.Months,
                               event = clinic.valid$surv.clinical.Event,
                               score = lp.RS.valid)
        res.mat[i,"bs.valid"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.valid, 
                               method="cox")$bsc.integrated
        
        # Log-rank.valid x2
        RS.2cl.valid <- rep(0, length = length(lp.RS.valid))
        RS.2cl.valid[which(lp.RS.valid >= median(lp.RS.train))] <- 1
        df.valid <- data.frame(bs.valid, RS.2cl = RS.2cl.valid)
        sdf <- try(survdiff(Surv(time,event)~RS.2cl, data=df.valid),
                   silent = TRUE)
        if(!('try-error' %in% class(sdf))){
            res.mat[i,"logrank.valid"] <- sdf$chisq
        }else{
            print(paste0("Valid set: Error in survdiff.fit, only 1 group!"))
        }
        
        # HR.valid
        lp.RS.valid.sd <- (lp.RS.valid - min(lp.RS.valid))/(max(lp.RS.valid) - min(lp.RS.valid))
        df.valid <- data.frame(df.valid, score.sd = lp.RS.valid.sd)
        res.mat[i,"HR.valid"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                               data = df.valid))$coefficients[2]
    }
    
}

# Summarize average performance
meanRes <- rep(0, length = 24)
medianRes <- rep(0, length = 24)
sdRes <- rep(0, length = 24)
RSDRes <- rep(0, length = 24)
for(i in seq_len(ncol(res.mat))){
    meanRes[i] <- mean(res.mat[,i], na.rm = TRUE)
    medianRes[i] <- median(res.mat[,i], na.rm = TRUE)
    sdRes[i] <- sd(res.mat[,i], na.rm = TRUE)
    RSDRes[i] <- 100*sdRes[i]/meanRes[i]
}
res.mean <- data.frame(mean = meanRes,
                       median = medianRes,
                       sd = sdRes,
                       RSD = RSDRes)
rownames(res.mean) <- colnames(res.mat)

res.CCPCA.ENCox <- list(res = res.mat,
                      res.mean = res.mean,
                      numOfFailed = numOfFailed)



# 11.4 sslasso -------------
# load data 

# IBM.224.mat, Clinic.224.df, IBM.88.mat, Clinic.88.df
load(file = "./RData/NSCLC.IBM.224.88.clinic.224.88.RData")


# normalization
IBM.224.mat.sd <- scale(IBM.224.mat, center = TRUE, scale = TRUE)
IBM.88.mat.sd <- scale(IBM.88.mat, center = TRUE, scale = TRUE)

# Load predefined random train-test splits 
load(file = "./RData/rslist.NSCLC.IBM.224.88.clinic.224.88.RData")

# load CC results
load(file = "./RData/consensus.Results.RData")
Feats.c1 <- names(which(results[[3]]$consensusClass==1))
Feats.c2 <- names(which(results[[3]]$consensusClass==2))
Feats.c3 <- names(which(results[[3]]$consensusClass==3))

# repeat 100 times
N <- 100

s0.seq <- seq(from = 0.0001, to = 0.099, by = 0.002)

# mod.PCA <- vector(mode = "list", length = N)

res.mat <- matrix(NA, nrow = N, ncol = 24)
colnames(res.mat) <- c("cindex.train", "AUC.1y.train", "AUC.3y.train",
                       "AUC.5y.train", "IAUC.train", "bs.train", "logrank.train", "HR.train",
                       "cindex.test",  "AUC.1y.test", "AUC.3y.test",  
                       "AUC.5y.test",  "IAUC.test", "bs.test", "logrank.test", "HR.test",
                       "cindex.valid", "AUC.1y.valid", "AUC.3y.valid", 
                       "AUC.5y.valid", "IAUC.valid", "bs.valid", "logrank.valid", "HR.valid")
numOfFailed <- 0

for(i in seq_len(N)){
    print(paste0("N: ",i, " ------------"))
    
    idx.train <- rslist[[i]]$idx.train
    idx.test <- rslist[[i]]$idx.test
    
    clinic.train <- Clinic.224.df[idx.train,]
    clinic.test <- Clinic.224.df[idx.test,]
    clinic.valid <- Clinic.88.df
    
    # c1uster 1
    Rad.train.c1 <- IBM.224.mat.sd[idx.train, Feats.c1]
    Rad.test.c1 <- IBM.224.mat.sd[idx.test,Feats.c1]
    Rad.valid.c1 <- IBM.88.mat.sd[,Feats.c1]
    
    pr.c1 <- prcomp(Rad.train.c1,
                    retx = TRUE, 
                    center = FALSE, 
                    scale = FALSE)   
    
    # Variance explained by principal components
    pr.var <- pr.c1$sdev^2
    pve <- pr.var/sum(pr.var)
    
    # Cumulative variance explained
    cumpve <- cumsum(pve)
    nSel.c1 <- which(cumpve > 0.95)[1]  # Select the number of principal components
    
    # c1uster 2
    Rad.train.c2 <- IBM.224.mat.sd[idx.train, Feats.c2]
    Rad.test.c2 <- IBM.224.mat.sd[idx.test,Feats.c2]
    Rad.valid.c2 <- IBM.88.mat.sd[,Feats.c2]
    
    pr.c2 <- prcomp(Rad.train.c2,
                    retx = TRUE, 
                    center = FALSE, 
                    scale = FALSE)   
    
    # Variance explained by principal components
    pr.var <- pr.c2$sdev^2
    pve <- pr.var/sum(pr.var)
    
    # Cumulative variance explained
    cumpve <- cumsum(pve)
    nSel.c2 <- which(cumpve > 0.95)[1]  # Select the number of principal components
    
    # c1uster 3
    Rad.train.c3 <- IBM.224.mat.sd[idx.train, Feats.c3]
    Rad.test.c3 <- IBM.224.mat.sd[idx.test,Feats.c3]
    Rad.valid.c3 <- IBM.88.mat.sd[,Feats.c3]
    
    pr.c3 <- prcomp(Rad.train.c3,
                    retx = TRUE, 
                    center = FALSE, 
                    scale = FALSE)   
    
    # Variance explained by principal components
    pr.var <- pr.c3$sdev^2
    pve <- pr.var/sum(pr.var)
    
    # Cumulative variance explained
    cumpve <- cumsum(pve)
    nSel.c3 <- which(cumpve > 0.95)[1]  # Select the number of principal components
    
    # train
    PCData.train.c1 <- pr.c1$x[,1:nSel.c1]
    colnames(PCData.train.c1) <- paste0("c1", colnames(PCData.train.c1))
    
    PCData.train.c2 <- pr.c2$x[,1:nSel.c2]
    colnames(PCData.train.c2) <- paste0("c2", colnames(PCData.train.c2))
    
    PCData.train.c3 <- pr.c3$x[,1:nSel.c3]
    colnames(PCData.train.c3) <- paste0("c3", colnames(PCData.train.c3))
    
    # test
    PCData.test.c1 <- Rad.test.c1%*%pr.c1$rotation[,1:nSel.c1]
    colnames(PCData.test.c1) <- paste0("c1", colnames(PCData.test.c1))
    
    PCData.test.c2 <- Rad.test.c2%*%pr.c2$rotation[,1:nSel.c2]
    colnames(PCData.test.c2) <- paste0("c2", colnames(PCData.test.c2))
    
    PCData.test.c3 <- Rad.test.c3%*%pr.c3$rotation[,1:nSel.c3]
    colnames(PCData.test.c3) <- paste0("c3", colnames(PCData.test.c3))
    
    # valid
    PCData.valid.c1 <- Rad.valid.c1%*%pr.c1$rotation[,1:nSel.c1]
    colnames(PCData.valid.c1) <- paste0("c1", colnames(PCData.valid.c1))
    
    PCData.valid.c2 <- Rad.valid.c2%*%pr.c2$rotation[,1:nSel.c2]
    colnames(PCData.valid.c2) <- paste0("c2", colnames(PCData.valid.c2))
    
    PCData.valid.c3 <- Rad.valid.c3%*%pr.c3$rotation[,1:nSel.c3]
    colnames(PCData.valid.c3) <- paste0("c3", colnames(PCData.valid.c3))
    
    PCData.train <- as.matrix(data.frame(PCData.train.c1,
                                         PCData.train.c2,
                                         PCData.train.c3))
    PCData.test <- as.matrix(data.frame(PCData.test.c1,
                                        PCData.test.c2,
                                        PCData.test.c3))
    PCData.valid <- as.matrix(data.frame(PCData.valid.c1,
                                         PCData.valid.c2,
                                         PCData.valid.c3))
    
    dev.seq <- c(NA, length = length(s0.seq))
    Cindex.seq <- c(NA, length = length(s0.seq))
    numOfFeats <- c(NA, length = length(s0.seq))
    mod.i.seq <-  vector(mode = "list", length = length(s0.seq))
    
    for(i.s0 in seq_len(length(s0.seq))){
        print(paste0("s0: ", i.s0, " -- ", s0.seq[i.s0]))
        mod.i.seq[[i.s0]] <- bmlasso(x = PCData.train,
                                     y = Surv(time = clinic.train$surv.clinical.Time.Months,
                                              event = clinic.train$surv.clinical.Event),
                                     family = "cox",
                                     ss = c(s0.seq[i.s0], 0.5)
        )
        numOfFeats[i.s0] <- mod.i.seq[[i.s0]]$df
        cv.s0 <- cv.bh(object = mod.i.seq[[i.s0]], nfolds = 10, ncv = 1, 
                       verbose = FALSE)
        dev.seq[i.s0] <- cv.s0$measures[1]
        Cindex.seq[i.s0] <- cv.s0$measures[2]
    }
    
    df.s0 <- data.frame(numOfFeats, dev.seq, Cindex.seq)
    
    # Select the minimum-deviance model among models with non-zero features
    idx.nzero <- which(numOfFeats != 0)
    if(length(idx.nzero) > 0){
        df.s0 <- df.s0[idx.nzero,]
        idx.mindev <- which.min(df.s0$dev.seq)  # Select the model with the minimum deviance
        mod.i <- mod.i.seq[[idx.nzero[idx.mindev]]]
        
        # mod.PCA[[i]] <- mod.i
        
        
        # RadScore-training set
        lp.RS.train <- as.vector(PCData.train %*% mod.i$coefficients)
        
        # 5-year AUC
        perf.RS.train.5y <- tdrocc(x = lp.RS.train,
                                   surv.time = clinic.train$surv.clinical.Time.Months,
                                   surv.event = clinic.train$surv.clinical.Event,
                                   time = 5*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.train"] <- perf.RS.train.5y$AUC
        
        # 3-year AUC
        perf.RS.train.3y <- tdrocc(x = lp.RS.train,
                                   surv.time = clinic.train$surv.clinical.Time.Months,
                                   surv.event = clinic.train$surv.clinical.Event,
                                   time = 3*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.train"] <- perf.RS.train.3y$AUC
        
        # 5-year AUC
        perf.RS.train.1y <- tdrocc(x = lp.RS.train,
                                   surv.time = clinic.train$surv.clinical.Time.Months,
                                   surv.event = clinic.train$surv.clinical.Event,
                                   time = 1*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.train"] <- perf.RS.train.1y$AUC
        
        res.mat[i,"cindex.train"] <- concordance.index(lp.RS.train, 
                                                       clinic.train$surv.clinical.Time.Months,
                                                       clinic.train$surv.clinical.Event)$c.index
        
        # IAUC.train
        tt.train <- unique(sort(clinic.train$surv.clinical.Time.Months[clinic.train$surv.clinical.Event == 1]))
        mytdroc.train <- NULL
        for(i.tt in 1:length(tt.train)) {
            rr.train <- tdrocc(x=lp.RS.train, 
                               surv.time=clinic.train$surv.clinical.Time.Months, 
                               surv.event=clinic.train$surv.clinical.Event, 
                               time=tt.train[i.tt],
                               na.rm=TRUE, verbose=FALSE)
            mytdroc.train <- c(mytdroc.train, list(rr.train))
        }
        auc.train <- unlist(lapply(mytdroc.train, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.train"] <- iauc.comp(auc1=auc.train, auc2=auc.train, time=tt.train)$iauc1
        
        # Brier score.train
        bs.train <- data.frame(time = clinic.train$surv.clinical.Time.Months,
                               event = clinic.train$surv.clinical.Event,
                               score = lp.RS.train)
        res.mat[i,"bs.train"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.train, 
                               method="cox")$bsc.integrated
        
        # Log-rank.train x2
        RS.2cl.train <- rep(0, length = length(lp.RS.train))
        RS.2cl.train[which(lp.RS.train >= median(lp.RS.train))] <- 1
        df.train <- data.frame(bs.train, RS.2cl = RS.2cl.train)
        sdf <- survdiff(Surv(time,event)~RS.2cl, data=df.train)
        res.mat[i,"logrank.train"] <- sdf$chisq
        
        # HR.train
        lp.RS.train.sd <- (lp.RS.train - min(lp.RS.train))/(max(lp.RS.train) - min(lp.RS.train))
        df.train <- data.frame(df.train, score.sd = lp.RS.train.sd)
        res.mat[i,"HR.train"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                               data = df.train))$coefficients[2]
        
        
        # test set
        lp.RS.test <- as.vector(PCData.test %*% mod.i$coefficients)
        
        
        # 5-year AUC
        perf.RS.test.5y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 5*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.test"] <- perf.RS.test.5y$AUC
        
        # 3-year AUC
        perf.RS.test.3y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 3*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.test"] <- perf.RS.test.3y$AUC
        
        # 1-year AUC
        perf.RS.test.1y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 1*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.test"] <- perf.RS.test.1y$AUC
        
        res.mat[i,"cindex.test"] <- concordance.index(lp.RS.test, 
                                                      clinic.test$surv.clinical.Time.Months,
                                                      clinic.test$surv.clinical.Event)$c.index
        # IAUC.test
        tt.test <- unique(sort(clinic.test$surv.clinical.Time.Months[clinic.test$surv.clinical.Event == 1]))
        mytdroc.test <- NULL
        for(i.tt in 1:length(tt.test)) {
            rr.test <- tdrocc(x=lp.RS.test, 
                              surv.time=clinic.test$surv.clinical.Time.Months, 
                              surv.event=clinic.test$surv.clinical.Event, 
                              time=tt.test[i.tt],
                              na.rm=TRUE, verbose=FALSE)
            mytdroc.test <- c(mytdroc.test, list(rr.test))
        }
        auc.test <- unlist(lapply(mytdroc.test, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.test"] <- iauc.comp(auc1=auc.test, auc2=auc.test, time=tt.test)$iauc1
        
        # Brier score
        bs.test <- data.frame(time = clinic.test$surv.clinical.Time.Months,
                              event = clinic.test$surv.clinical.Event,
                              score = lp.RS.test)
        res.mat[i,"bs.test"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.test, 
                               method="cox")$bsc.integrated
        
        # Log-rank.test x2
        RS.2cl.test <- rep(0, length = length(lp.RS.test))
        RS.2cl.test[which(lp.RS.test >= median(lp.RS.train))] <- 1
        df.test <- data.frame(bs.test, RS.2cl = RS.2cl.test)
        sdf <- try(survdiff(Surv(time,event)~RS.2cl, data=df.test),
                   silent = TRUE)
        if(!('try-error' %in% class(sdf))){
            res.mat[i,"logrank.test"] <- sdf$chisq
        }else{
            print(paste0("Test set: Error in survdiff.fit, only 1 group!"))
        }
        
        
        # HR.test
        lp.RS.test.sd <- (lp.RS.test - min(lp.RS.test))/(max(lp.RS.test) - min(lp.RS.test))
        df.test <- data.frame(df.test, score.sd = lp.RS.test.sd)
        res.mat[i,"HR.test"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                              data = df.test))$coefficients[2]
        
        
        # valid set
        lp.RS.valid <- as.vector(PCData.valid %*% mod.i$coefficients)
        
        
        # 5-year AUC
        perf.RS.valid.5y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 5*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.valid"] <- perf.RS.valid.5y$AUC
        
        # 3-year AUC
        perf.RS.valid.3y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 3*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.valid"] <- perf.RS.valid.3y$AUC
        
        # 1-year AUC
        perf.RS.valid.1y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 1*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.valid"] <- perf.RS.valid.1y$AUC
        
        res.mat[i,"cindex.valid"] <- concordance.index(lp.RS.valid, 
                                                       clinic.valid$surv.clinical.Time.Months,
                                                       clinic.valid$surv.clinical.Event)$c.index
        # IAUC.valid
        tt.valid <- unique(sort(clinic.valid$surv.clinical.Time.Months[clinic.valid$surv.clinical.Event == 1]))
        mytdroc.valid <- NULL
        for(i.tt in 1:length(tt.valid)) {
            rr.valid <- tdrocc(x=lp.RS.valid, 
                               surv.time=clinic.valid$surv.clinical.Time.Months, 
                               surv.event=clinic.valid$surv.clinical.Event, 
                               time=tt.valid[i.tt],
                               na.rm=TRUE, verbose=FALSE)
            mytdroc.valid <- c(mytdroc.valid, list(rr.valid))
        }
        auc.valid <- unlist(lapply(mytdroc.valid, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.valid"] <- iauc.comp(auc1=auc.valid, auc2=auc.valid, time=tt.valid)$iauc1
        
        # Brier score
        bs.valid <- data.frame(time = clinic.valid$surv.clinical.Time.Months,
                               event = clinic.valid$surv.clinical.Event,
                               score = lp.RS.valid)
        res.mat[i,"bs.valid"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.valid, 
                               method="cox")$bsc.integrated
        
        # Log-rank.valid x2
        RS.2cl.valid <- rep(0, length = length(lp.RS.valid))
        RS.2cl.valid[which(lp.RS.valid >= median(lp.RS.train))] <- 1
        df.valid <- data.frame(bs.valid, RS.2cl = RS.2cl.valid)
        sdf <- try(survdiff(Surv(time,event)~RS.2cl, data=df.valid),
                   silent = TRUE)
        if(!('try-error' %in% class(sdf))){
            res.mat[i,"logrank.valid"] <- sdf$chisq
        }else{
            print(paste0("Valid set: Error in survdiff.fit, only 1 group!"))
        }
        
        # HR.valid
        lp.RS.valid.sd <- (lp.RS.valid - min(lp.RS.valid))/(max(lp.RS.valid) - min(lp.RS.valid))
        df.valid <- data.frame(df.valid, score.sd = lp.RS.valid.sd)
        res.mat[i,"HR.valid"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                               data = df.valid))$coefficients[2]
    }else{
        print(paste0("N: ", i, ", No feats selected!"))
        numOfFailed <- numOfFailed + 1
    }
}

# Summarize average performance
meanRes <- rep(0, length = 24)
medianRes <- rep(0, length = 24)
sdRes <- rep(0, length = 24)
RSDRes <- rep(0, length = 24)
for(i in seq_len(ncol(res.mat))){
    meanRes[i] <- mean(res.mat[,i], na.rm = TRUE)
    medianRes[i] <- median(res.mat[,i], na.rm = TRUE)
    sdRes[i] <- sd(res.mat[,i], na.rm = TRUE)
    RSDRes[i] <- 100*sdRes[i]/meanRes[i]
}

res.mean <- data.frame(mean = meanRes,
                       median = medianRes,
                       sd = sdRes,
                       RSD = RSDRes)
rownames(res.mean) <- colnames(res.mat)

res.CCPCA.sslasso <- list(res = res.mat,
                        res.mean = res.mean,
                        numOfFailed = numOfFailed)


