library("abess")
# load data 

# IBM.224.mat, Clinic.224.df, IBM.88.mat, Clinic.88.df
load(file = "./RData/NSCLC.IBM.224.88.clinic.224.88.RData")


# normalization
IBM.224.mat.sd <- scale(IBM.224.mat, center = TRUE, scale = TRUE)
IBM.88.mat.sd <- scale(IBM.88.mat, center = TRUE, scale = TRUE)

# Load predefined random train-test splits 
load(file = "./RData/rslist.NSCLC.IBM.224.88.clinic.224.88.RData")

# load CC results
load(file = "./RData/consensus.Results.RData")
Feats.c1 <- names(which(results[[3]]$consensusClass==1))
Feats.c2 <- names(which(results[[3]]$consensusClass==2))
Feats.c3 <- names(which(results[[3]]$consensusClass==3))

# repeat 100 times
N <- 100

# mod.abess <- vector(mode = "list", length = N)

res.mat <- matrix(NA, nrow = N, ncol = 24)
colnames(res.mat) <- c("cindex.train", "AUC.1y.train", "AUC.3y.train",
                       "AUC.5y.train", "IAUC.train", "bs.train", "logrank.train", "HR.train",
                       "cindex.test",  "AUC.1y.test", "AUC.3y.test",  
                       "AUC.5y.test",  "IAUC.test", "bs.test", "logrank.test", "HR.test",
                       "cindex.valid", "AUC.1y.valid", "AUC.3y.valid", 
                       "AUC.5y.valid", "IAUC.valid", "bs.valid", "logrank.valid", "HR.valid")
numOfFailed <- 0

for(i in seq_len(N)){
    print(paste0("N: ",i, " ------------"))
    
    idx.train <- rslist[[i]]$idx.train
    idx.test <- rslist[[i]]$idx.test
    
    clinic.train <- Clinic.224.df[idx.train,]
    clinic.test <- Clinic.224.df[idx.test,]
    clinic.valid <- Clinic.88.df
    
    # c1uster 1
    Rad.train.c1 <- IBM.224.mat.sd[idx.train, Feats.c1]
    Rad.test.c1 <- IBM.224.mat.sd[idx.test,Feats.c1]
    Rad.valid.c1 <- IBM.88.mat.sd[,Feats.c1]
    
    pr.c1 <- prcomp(Rad.train.c1,
                    retx = TRUE, 
                    center = FALSE, 
                    scale = FALSE)   
    
    # Variance explained by principal components
    pr.var <- pr.c1$sdev^2
    pve <- pr.var/sum(pr.var)
    
    # Cumulative variance explained
    cumpve <- cumsum(pve)
    nSel.c1 <- which(cumpve > 0.95)[1]  # Select the number of principal components
    
    # c1uster 2
    Rad.train.c2 <- IBM.224.mat.sd[idx.train, Feats.c2]
    Rad.test.c2 <- IBM.224.mat.sd[idx.test,Feats.c2]
    Rad.valid.c2 <- IBM.88.mat.sd[,Feats.c2]
    
    pr.c2 <- prcomp(Rad.train.c2,
                    retx = TRUE, 
                    center = FALSE, 
                    scale = FALSE)   
    
    # Variance explained by principal components
    pr.var <- pr.c2$sdev^2
    pve <- pr.var/sum(pr.var)
    
    # Cumulative variance explained
    cumpve <- cumsum(pve)
    nSel.c2 <- which(cumpve > 0.95)[1]  # Select the number of principal components
    
    # c1uster 3
    Rad.train.c3 <- IBM.224.mat.sd[idx.train, Feats.c3]
    Rad.test.c3 <- IBM.224.mat.sd[idx.test,Feats.c3]
    Rad.valid.c3 <- IBM.88.mat.sd[,Feats.c3]
    
    pr.c3 <- prcomp(Rad.train.c3,
                    retx = TRUE, 
                    center = FALSE, 
                    scale = FALSE)   
    
    # Variance explained by principal components
    pr.var <- pr.c3$sdev^2
    pve <- pr.var/sum(pr.var)
    
    # Cumulative variance explained
    cumpve <- cumsum(pve)
    nSel.c3 <- which(cumpve > 0.95)[1]  # Select the number of principal components
    
    # train
    PCData.train.c1 <- pr.c1$x[,1:nSel.c1]
    colnames(PCData.train.c1) <- paste0("c1", colnames(PCData.train.c1))
    
    PCData.train.c2 <- pr.c2$x[,1:nSel.c2]
    colnames(PCData.train.c2) <- paste0("c2", colnames(PCData.train.c2))
    
    PCData.train.c3 <- pr.c3$x[,1:nSel.c3]
    colnames(PCData.train.c3) <- paste0("c3", colnames(PCData.train.c3))
    
    # test
    PCData.test.c1 <- Rad.test.c1%*%pr.c1$rotation[,1:nSel.c1]
    colnames(PCData.test.c1) <- paste0("c1", colnames(PCData.test.c1))
    
    PCData.test.c2 <- Rad.test.c2%*%pr.c2$rotation[,1:nSel.c2]
    colnames(PCData.test.c2) <- paste0("c2", colnames(PCData.test.c2))
    
    PCData.test.c3 <- Rad.test.c3%*%pr.c3$rotation[,1:nSel.c3]
    colnames(PCData.test.c3) <- paste0("c3", colnames(PCData.test.c3))
    
    # valid
    PCData.valid.c1 <- Rad.valid.c1%*%pr.c1$rotation[,1:nSel.c1]
    colnames(PCData.valid.c1) <- paste0("c1", colnames(PCData.valid.c1))
    
    PCData.valid.c2 <- Rad.valid.c2%*%pr.c2$rotation[,1:nSel.c2]
