    PCData.test.c2 <- Rad.test.c2%*%pr.c2$rotation[,1:nSel.c2]
    colnames(PCData.test.c2) <- paste0("c2", colnames(PCData.test.c2))
    
    PCData.test.c3 <- Rad.test.c3%*%pr.c3$rotation[,1:nSel.c3]
    colnames(PCData.test.c3) <- paste0("c3", colnames(PCData.test.c3))
    
    # valid
    PCData.valid.c1 <- Rad.valid.c1%*%pr.c1$rotation[,1:nSel.c1]
    colnames(PCData.valid.c1) <- paste0("c1", colnames(PCData.valid.c1))
    
    PCData.valid.c2 <- Rad.valid.c2%*%pr.c2$rotation[,1:nSel.c2]
    colnames(PCData.valid.c2) <- paste0("c2", colnames(PCData.valid.c2))
    
    PCData.valid.c3 <- Rad.valid.c3%*%pr.c3$rotation[,1:nSel.c3]
    colnames(PCData.valid.c3) <- paste0("c3", colnames(PCData.valid.c3))
    
    PCData.train <- data.frame(PCData.train.c1,
                               PCData.train.c2,
                               PCData.train.c3,
                               time = clinic.train$`surv.clinical.Time.Months`,
                               status = clinic.train$`surv.clinical.Event`)
    PCData.test <- data.frame(PCData.test.c1,
                              PCData.test.c2,
                              PCData.test.c3,
                              time = clinic.test$`surv.clinical.Time.Months`,
                              status = clinic.test$`surv.clinical.Event`)
    PCData.valid <- data.frame(PCData.valid.c1,
                               PCData.valid.c2,
                               PCData.valid.c3,
                               time = clinic.valid$`surv.clinical.Time.Months`,
                               status = clinic.valid$`surv.clinical.Event`)
    
    
    mod.i <- try(coxph(Surv(time, status)~., data = PCData.train), #quadprog
                 silent = TRUE)
    if(!('try-error' %in% class(mod.i))){
