        # Log-rank.train x2
        RS.2cl.train <- rep(0, length = length(lp.RS.train))
        RS.2cl.train[which(lp.RS.train > median(lp.RS.train))] <- 1
        df.train <- data.frame(bs.train, RS.2cl = RS.2cl.train)
        sdf <- survdiff(Surv(time,event)~RS.2cl, data=df.train)
        res.mat[i,"logrank.train"] <- sdf$chisq
        
        # HR.train
        lp.RS.train.sd <- (lp.RS.train - min(lp.RS.train))/(max(lp.RS.train) - min(lp.RS.train))
        df.train <- data.frame(df.train, score.sd = lp.RS.train.sd)
        hr.train <- try(coxph(Surv(time, event) ~ score.sd, data = df.train),
                        silent = TRUE)
        if(!('try-error' %in% class(hr.train))){
            res.mat[i,"HR.train"] <- summary(hr.train)$coefficients[2]
        }else{
            print(paste0("Training set: Error in HR.valid!"))
        }
    }else{
        print("Training set: all predictions are 0s!")
        print(lp.RS.train)
    }
    
    
    
    # test set
    pred.test = lrn.cur$predict(task.test)
    lp.RS.test <- pred.test$crank
    
    if(length(unique(lp.RS.test)) > 1){
        # 5-year AUC
        perf.RS.test.5y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 5*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.test"] <- perf.RS.test.5y$AUC
        
        # 3-year AUC
        perf.RS.test.3y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 3*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.test"] <- perf.RS.test.3y$AUC
        
        # 1-year AUC
        perf.RS.test.1y <- tdrocc(x = lp.RS.test,
                                  surv.time = clinic.test$surv.clinical.Time.Months,
                                  surv.event = clinic.test$surv.clinical.Event,
                                  time = 1*12, #max(myData$time)*1.05, 
                                  cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.test"] <- perf.RS.test.1y$AUC
        
        res.mat[i,"cindex.test"] <- concordance.index(lp.RS.test, 
                                                      clinic.test$surv.clinical.Time.Months,
                                                      clinic.test$surv.clinical.Event)$c.index
        
        # IAUC.test
        tt.test <- unique(sort(clinic.test$surv.clinical.Time.Months[clinic.test$surv.clinical.Event == 1]))
        mytdroc.test <- NULL
        for(i.tt in 1:length(tt.test)) {
            rr.test <- tdrocc(x=lp.RS.test, 
                              surv.time=clinic.test$surv.clinical.Time.Months, 
                              surv.event=clinic.test$surv.clinical.Event, 
                              time=tt.test[i.tt],
                              na.rm=TRUE, verbose=FALSE)
            mytdroc.test <- c(mytdroc.test, list(rr.test))
        }
        auc.test <- unlist(lapply(mytdroc.test, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.test"] <- iauc.comp(auc1=auc.test, auc2=auc.test, time=tt.test)$iauc1
        
        # Brier score
        bs.test <- data.frame(time = clinic.test$surv.clinical.Time.Months,
                              event = clinic.test$surv.clinical.Event,
                              score = lp.RS.test)
        res.mat[i,"bs.test"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.test, 
                               method="cox")$bsc.integrated
        
        # Log-rank.test x2
        RS.2cl.test <- rep(0, length = length(lp.RS.test))
        RS.2cl.test[which(lp.RS.test > median(lp.RS.train))] <- 1
        df.test <- data.frame(bs.test, RS.2cl = RS.2cl.test)
        sdf <- try(survdiff(Surv(time,event)~RS.2cl, data=df.test),
                   silent = TRUE)
        if(!('try-error' %in% class(sdf))){
            res.mat[i,"logrank.test"] <- sdf$chisq
        }else{
            print(paste0("Test set: Error in survdiff.fit, only 1 group!"))
        }
        
        
        # HR.test
        lp.RS.test.sd <- (lp.RS.test - min(lp.RS.test))/(max(lp.RS.test) - min(lp.RS.test))
        df.test <- data.frame(df.test, score.sd = lp.RS.test.sd)
        hr.test <- try(coxph(Surv(time, event) ~ score.sd, data = df.test),
                       silent = TRUE)
        if(!('try-error' %in% class(hr.test))){
            res.mat[i,"HR.test"] <- summary(hr.test)$coefficients[2]
        }else{
            print(paste0("Test set: Error in HR.test!"))
        }
    }else{
        print("Test set: all preditions are 0s!")
        print(lp.RS.test)
    } 
    
    
    # valid set
    pred.valid = lrn.cur$predict(task.valid)
    lp.RS.valid <- pred.valid$crank
    
    if(length(unique(lp.RS.valid)) > 1){
        # 5-year AUC
        perf.RS.valid.5y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 5*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.5y.valid"] <- perf.RS.valid.5y$AUC
        
        # 3-year AUC
        perf.RS.valid.3y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 3*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.3y.valid"] <- perf.RS.valid.3y$AUC
        
        # 1-year AUC
        perf.RS.valid.1y <- tdrocc(x = lp.RS.valid,
                                   surv.time = clinic.valid$surv.clinical.Time.Months,
                                   surv.event = clinic.valid$surv.clinical.Event,
                                   time = 1*12, #max(myData$time)*1.05, 
                                   cutpts = NA, na.rm = TRUE)
        res.mat[i,"AUC.1y.valid"] <- perf.RS.valid.1y$AUC
        
        res.mat[i,"cindex.valid"] <- concordance.index(lp.RS.valid, 
                                                       clinic.valid$surv.clinical.Time.Months,
                                                       clinic.valid$surv.clinical.Event)$c.index
        # IAUC.valid
        tt.valid <- unique(sort(clinic.valid$surv.clinical.Time.Months[clinic.valid$surv.clinical.Event == 1]))
        mytdroc.valid <- NULL
        for(i.tt in 1:length(tt.valid)) {
            rr.valid <- tdrocc(x=lp.RS.valid, 
                               surv.time=clinic.valid$surv.clinical.Time.Months, 
                               surv.event=clinic.valid$surv.clinical.Event, 
                               time=tt.valid[i.tt],
                               na.rm=TRUE, verbose=FALSE)
            mytdroc.valid <- c(mytdroc.valid, list(rr.valid))
        }
        auc.valid <- unlist(lapply(mytdroc.valid, function(x) { return(x$AUC) }))
        
        res.mat[i,"IAUC.valid"] <- iauc.comp(auc1=auc.valid, auc2=auc.valid, time=tt.valid)$iauc1
        
        # Brier score
        bs.valid <- data.frame(time = clinic.valid$surv.clinical.Time.Months,
                               event = clinic.valid$surv.clinical.Event,
                               score = lp.RS.valid)
        res.mat[i,"bs.valid"] <- 
            sbrier.score2proba(data.tr=bs.train, data.ts=bs.valid, 
                               method="cox")$bsc.integrated
        
        # Log-rank.valid x2
        RS.2cl.valid <- rep(0, length = length(lp.RS.valid))
        RS.2cl.valid[which(lp.RS.valid > median(lp.RS.train))] <- 1
        df.valid <- data.frame(bs.valid, RS.2cl = RS.2cl.valid)
        sdf <- try(survdiff(Surv(time,event)~RS.2cl, data=df.valid),
                   silent = TRUE)
        if(!('try-error' %in% class(sdf))){
            res.mat[i,"logrank.valid"] <- sdf$chisq
        }else{
            print(paste0("Valid set: Error in survdiff.fit, only 1 group!"))
        }
        
        # HR.valid
        lp.RS.valid.sd <- (lp.RS.valid - min(lp.RS.valid))/(max(lp.RS.valid) - min(lp.RS.valid))
        df.valid <- data.frame(df.valid, score.sd = lp.RS.valid.sd)
        hr.valid <- try(coxph(Surv(time, event) ~ score.sd, data = df.valid),
                        silent = TRUE)
        if(!('try-error' %in% class(hr.valid))){
            res.mat[i,"HR.valid"] <- summary(hr.valid)$coefficients[2]
        }else{
            print(paste0("Valid set: Error in HR.valid!"))
        }
    }else{
        print("Valid set: all preditions are 0s!")
        print(lp.RS.valid)
    }
}

# Summarize average performance
meanRes <- rep(0, length = 24)
medianRes <- rep(0, length = 24)
sdRes <- rep(0, length = 24)
RSDRes <- rep(0, length = 24)
for(i in seq_len(ncol(res.mat))){
    meanRes[i] <- mean(res.mat[,i], na.rm = TRUE)
    medianRes[i] <- median(res.mat[,i], na.rm = TRUE)
    sdRes[i] <- sd(res.mat[,i], na.rm = TRUE)
    RSDRes[i] <- 100*sdRes[i]/meanRes[i]
}
res.mean <- data.frame(mean = meanRes,
                       median = medianRes,
                       sd = sdRes,
                       RSD = RSDRes)
rownames(res.mean) <- colnames(res.mat)

res.CCPCA.deepsurv <- list(res = res.mat,
                         res.mean = res.mean,
                         numOfFailed = numOfFailed)


# 11.13 DeepHit ---------------
# 11.13.1 Hyperparameter tuning for DeepHit---------------
# load data 
library(reticulate)
library(survivalmodels)
library(mlr3)
library(mlr3proba)
library(paradox) # Define and Work with Parameter Spaces for Complex Algorithms
library(mlr3tuning)
library(mlr3extralearners)## learners are stored in mlr3extralearners
library("keras")
library("tensorflow")

# IBM.224.mat, Clinic.224.df, IBM.88.mat, Clinic.88.df
load(file = "./RData/NSCLC.IBM.224.88.clinic.224.88.RData")


# normalization
IBM.224.mat.sd <- scale(IBM.224.mat, center = TRUE, scale = TRUE)
IBM.88.mat.sd <- scale(IBM.88.mat, center = TRUE, scale = TRUE)

# load Feats with CoxP<0.1
# load(file = "./RData/Feats.CoxP.0.1.NSCLC.IBM.224.88.clinic.224.88.RData")
# Feats

# load CC results
load(file = "./RData/consensus.Results.RData")
Feats.c1 <- names(which(results[[3]]$consensusClass==1))
Feats.c2 <- names(which(results[[3]]$consensusClass==2))
Feats.c3 <- names(which(results[[3]]$consensusClass==3))

# c1uster 1
Rad.c1 <- IBM.224.mat.sd[, Feats.c1]

pr.c1 <- prcomp(Rad.c1,
                retx = TRUE, 
                center = FALSE, 
                scale = FALSE)   

# Variance explained by principal components
pr.var <- pr.c1$sdev^2
pve <- pr.var/sum(pr.var)

# Cumulative variance explained
cumpve <- cumsum(pve)
nSel.c1 <- which(cumpve > 0.95)[1]  # Select the number of principal components

# c1uster 2
Rad.c2 <- IBM.224.mat.sd[, Feats.c2]

pr.c2 <- prcomp(Rad.c2,
                retx = TRUE, 
                center = FALSE, 
                scale = FALSE)   

# Variance explained by principal components
pr.var <- pr.c2$sdev^2
pve <- pr.var/sum(pr.var)

# Cumulative variance explained
cumpve <- cumsum(pve)
nSel.c2 <- which(cumpve > 0.95)[1]  # Select the number of principal components

# c1uster 3
Rad.c3 <- IBM.224.mat.sd[, Feats.c3]

pr.c3 <- prcomp(Rad.c3,
                retx = TRUE, 
                center = FALSE, 
                scale = FALSE)   

# Variance explained by principal components
pr.var <- pr.c3$sdev^2
pve <- pr.var/sum(pr.var)

# Cumulative variance explained
cumpve <- cumsum(pve)
nSel.c3 <- which(cumpve > 0.95)[1]  # Select the number of principal components

# train
PCData.c1 <- pr.c1$x[,1:nSel.c1]
colnames(PCData.c1) <- paste0("c1", colnames(PCData.c1))

PCData.c2 <- pr.c2$x[,1:nSel.c2]
colnames(PCData.c2) <- paste0("c2", colnames(PCData.c2))

PCData.c3 <- pr.c3$x[,1:nSel.c3]
colnames(PCData.c3) <- paste0("c3", colnames(PCData.c3))

RadC.224 <- data.frame(PCData.c1,
                       PCData.c2,
                       PCData.c3,
                       time = Clinic.224.df$`surv.clinical.Time.Months`,
                       status = Clinic.224.df$`surv.clinical.Event`)

## create our own task
task.NSCLC <- TaskSurv$new(id = "NSCLC", # task id
                           backend = RadC.224,  # data, data.table or data.frame
                           time = "time",  # Name of the column for event time
                           event = "status") # Name of the column giving the event indicator
# "0"/FALSE means alive (no event), "1"/TRUE means dead (event)

# Hyperparameter tuning
lrn.deephit <- lrn("surv.deephit", 
                   frac = 0.3,  # Fraction of data to use for validation dataset
                   early_stopping = TRUE, 
                   epochs = 500, 
                   batch_norm = TRUE # batch normalisation
                   # optimizer = "adam",
)

# lrn.deephit$param_set

search_space <- ps(
    ## p_dbl for numeric valued parameters
    activation = p_fct(levels = c("relu", "selu")),  
    dropout = p_dbl(lower = 0, upper = 0.8),  # 
    weight_decay = p_dbl(lower = 0, upper = 0.5), # Passed to all methods except rprop and sparse_adam
    # learning_rate = p_dbl(lower = 1e-4, upper = 1),
    learning_rate = p_dbl(lower = 1, upper = 9, trafo = function(x) exp(x)/exp(10)),
    optimizer = p_fct(levels = c("adam", "sgd")),
    # momentum = p_dbl(lower = 0, upper = 1), 
    
    ## p_int for integer valued parameters
    nodes = p_int(lower = 2, upper = 7), # the number of nodes in a layer
    k = p_int(lower = 1, upper = 4),  # the number of layers
    .extra_trafo = function(x, param_set) {
        # x$num_nodes = c()
        # n_layers = x$k
        # for(n_l in seq_len(n_layers)){
        #     x$num_nodes = c(x$num_nodes, sample(c(4,8,16,24,32,64),1))
        # }
        x$num_nodes = rep(2^(x$nodes), x$k)
        x$nodes = x$k = NULL
        # x$k = NULL
        if(x$optimizer == "sgd"){
            x$momentum = 0.8 #runif(1, 0.8,0.95)
        }
        return(x)
    }
)

## select holdout as the resampling strategy
resampling <- rsmp("cv", folds = 3)
resampling <- rsmp("repeated_cv", repeats = 5, folds = 3)

# hout = rsmp("holdout")
measure = msr("surv.cindex")

library("mlr3tuning")
# Terminate after a given time (TerminatorClockTime).
# Terminate after a given number of iterations (TerminatorEvals).
# Terminate after a specific performance has been reached (TerminatorPerfReached).
# Terminate when tuning does find a better configuration for a given number of iterations (TerminatorStagnation).
# A combination of the above in an ALL or ANY fashion (TerminatorCombo).
evals20 = trm("evals", n_evals = 2)
trm10 = trm("stagnation", iters = 3000, threshold = 1e-5)
trm.comb = trm("combo",
               list(
                   trm("clock_time", stop_time = Sys.time() + 72000),
                   trm("stagnation", iters = 6000, threshold = 1e-5)
               ), any = TRUE)

instance = TuningInstanceSingleCrit$new(
    task = task.NSCLC,
    learner = lrn.deephit,
    resampling = resampling,
    measure = measure,
    search_space = search_space,
    terminator =   trm.comb#  evals20#  
)
instance

tuner = tnr("random_search", batch_size = 5)  # Maximum number of points to try in a batch.
tuner = tnr("grid_search",
            param_resolutions = c("dropout" = 20,
                                  "learning_rate" = 20,
                                  "weight_decay" = 10),
            batch_size = 5)  # Maximum number of points to try in a batch.
tuner$optimize(instance)
instance$result_learner_param_vals   # Optimal parameters
instance$result_y   # Optimal results
# as.data.table(instance$archive)  # All results
# instance$archive$benchmark_result


lrn.deephit$param_set$values = instance$result_learner_param_vals  # select optimal parameters

save(lrn.deephit, file = "./RData/lrn.deephit.CCPCA.NSCLC.IBM.224.88.clinic.224.88.RData")


