    PCData.train <- pr$S
    PCData.test <- Rad.test %*% pr$K %*% pr$W
    PCData.valid <- Rad.valid %*% pr$K %*% pr$W
    
    
    cv.res <- cv.CoxBoost(time = clinic.train$surv.clinical.Time.Months,
                          status = clinic.train$surv.clinical.Event,
                          x = PCData.train,
                          maxstepno=500,
                          K=5,
                          type="verweij",
                          penalty=1000)
    
    
    if(cv.res$optimal.step ==0){
