        }else{
            print(paste0("Valid set: Error in survdiff.fit, only 1 group!"))
        }
        
        # HR.valid
        lp.RS.valid.sd <- (lp.RS.valid - min(lp.RS.valid))/(max(lp.RS.valid) - min(lp.RS.valid))
        df.valid <- data.frame(df.valid, score.sd = lp.RS.valid.sd)
        res.mat[i,"HR.valid"] <- summary(coxph(Surv(time, event) ~ score.sd, 
                                               data = df.valid))$coefficients[2]
        
    }else{
        print(paste0("Gamma = ", g, ", No solution!"))
        numOfFailed <- numOfFailed + 1
